// Sabores del Mundo — datos de recetas
// Para agregar o editar recetas, modifica los objetos de este arreglo.
const RECETAS = [
{id:"ar-01",pais:"Argentina",nombre:"Asado con chimichurri",desc:"El rito argentino por excelencia: cortes de res cocidos lentamente sobre brasas y acompañados de chimichurri fresco.",tiempo:150,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["2 kg de tira de asado","1 kg de vacío","Sal gruesa","1 taza de perejil picado","4 dientes de ajo picados","1 cda de orégano seco","1 cdita de ají molido","1/2 taza de aceite de oliva","1/4 taza de vinagre de vino","1/4 taza de agua tibia"],pasos:["Prepara el chimichurri mezclando perejil, ajo, orégano, ají molido, vinagre, agua y aceite; deja reposar al menos 1 hora.","Enciende el fuego con leña o carbón y espera a tener brasas parejas, sin llama.","Sala la carne con sal gruesa por ambos lados.","Coloca la tira de asado con el hueso hacia abajo y cocina a fuego suave 60–80 minutos.","Da vuelta los cortes y termina la cocción hasta que estén dorados por fuera y jugosos por dentro.","Sirve recién cortado con chimichurri por encima."],ilu:{t:"plato",c:["#8C4A32","#5C8A4E","#C0392B"]}},
{id:"ar-02",pais:"Argentina",nombre:"Empanadas criollas",desc:"Empanadas de carne cortada a cuchillo con cebolla, huevo y aceitunas, horneadas hasta dorar.",tiempo:90,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["500 g de carne de res picada a cuchillo","2 cebollas picadas","1 cebolla de verdeo","2 huevos duros picados","12 aceitunas verdes","1 cdita de comino","1 cda de pimentón dulce","Sal y pimienta","12 tapas de empanada para horno","1 huevo batido para pintar"],pasos:["Rehoga la cebolla en un poco de grasa o aceite hasta que esté transparente.","Agrega la carne, el comino y el pimentón; cocina 10 minutos y salpimienta.","Deja enfriar el relleno y mezcla con el huevo duro, la aceituna y el verdeo.","Rellena las tapas, humedece los bordes y cierra con repulgue.","Pinta con huevo batido y hornea a 220 °C por 15–18 minutos hasta dorar.","Sirve calientes, idealmente acompañadas de un buen vino tinto."],ilu:{t:"empanada",c:["#E3B23C","#C98B2D","#8C4A32"]}},
{id:"ar-03",pais:"Argentina",nombre:"Milanesa a la napolitana",desc:"Milanesa de res cubierta con salsa de tomate, jamón y queso gratinado: un clásico de bodegón.",tiempo:45,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["4 filetes de nalga o bola de lomo","2 huevos","2 dientes de ajo picados","Perejil picado","300 g de pan rallado","1 taza de salsa de tomate","4 fetas de jamón cocido","200 g de muzzarella","Aceite para freír","Sal y pimienta"],pasos:["Bate los huevos con ajo, perejil, sal y pimienta.","Pasa los filetes por el huevo y luego por pan rallado, presionando bien.","Fríe las milanesas en aceite caliente hasta dorar y escurre sobre papel.","Cubre cada milanesa con salsa de tomate, jamón y muzzarella.","Gratina en horno fuerte 5–8 minutos hasta fundir el queso.","Sirve con papas fritas o puré."],ilu:{t:"plato",c:["#D9A05B","#C0392B","#F2E3C2"]}},
{id:"ar-04",pais:"Argentina",nombre:"Locro",desc:"Guiso espeso de maíz blanco, porotos, zapallo y carnes, infaltable en las fiestas patrias.",tiempo:180,porciones:8,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["500 g de maíz blanco pisado (remojado desde la víspera)","250 g de porotos pallares (remojados)","500 g de falda de res","2 chorizos","150 g de panceta","500 g de zapallo en cubos","1 cebolla","2 cebollas de verdeo","1 cda de pimentón","1 cdita de ají molido"],pasos:["Hierve el maíz y los porotos escurridos en abundante agua durante 1 hora.","Agrega la falda, la panceta y el chorizo en trozos; cocina 1 hora más a fuego bajo.","Suma el zapallo y la cebolla picada y cocina hasta que el guiso espese, revolviendo para que no se pegue.","Prepara la salsa picante: rehoga verdeo con pimentón y ají molido en aceite.","Ajusta la sal y sirve bien caliente con un chorrito de la salsa por encima."],ilu:{t:"bowl",c:["#DD8436","#EFC94C","#5C8A4E"]}},
{id:"ar-05",pais:"Argentina",nombre:"Provoleta",desc:"Queso provolone dorado a la parrilla con orégano y ají molido, la entrada favorita del asado.",tiempo:20,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["4 rodajas gruesas de queso provolone (2 cm)","1 cda de orégano seco","1 cdita de ají molido","Aceite de oliva","Pan crocante para acompañar"],pasos:["Deja orear el queso 1 hora a temperatura ambiente para que forme costra al cocinarse.","Calienta bien la plancha o provoletera sobre las brasas.","Coloca el queso y cocina sin moverlo hasta que dore la base.","Da vuelta con cuidado, espolvorea orégano y ají molido.","Retira cuando esté fundido por dentro y crocante por fuera; sirve de inmediato con pan."],ilu:{t:"plato",c:["#F2E3C2","#E3B23C","#5C8A4E"]}},
{id:"ar-06",pais:"Argentina",nombre:"Choripán",desc:"Chorizo a la parrilla en pan crocante con chimichurri: el sándwich callejero argentino.",tiempo:30,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:1,ingredientes:["4 chorizos de cerdo","4 panes tipo baguette chica","Chimichurri","Salsa criolla (tomate, cebolla, morrón, vinagre)"],pasos:["Cocina los chorizos a fuego medio en la parrilla unos 20 minutos, girándolos.","Ábrelos al medio (mariposa) y dóralos 2 minutos por el corte.","Tuesta levemente el pan sobre la parrilla.","Arma el sándwich con el chorizo y abundante chimichurri o salsa criolla.","Sirve caliente, sin cubiertos y sin culpa."],ilu:{t:"sandwich",c:["#D9A05B","#8C4A32","#5C8A4E"]}},
{id:"ar-07",pais:"Argentina",nombre:"Humita en chala",desc:"Pasta cremosa de choclo y albahaca envuelta en hojas de maíz y cocida al vapor.",tiempo:90,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["8 choclos con sus hojas (chalas)","1 cebolla picada","1 morrón rojo picado","Hojas de albahaca","100 g de queso cremoso (opcional)","1 cdita de pimentón","Leche (si hace falta aligerar)","Sal y pimienta"],pasos:["Reserva las chalas más grandes y ralla o procesa los granos de choclo.","Rehoga cebolla y morrón, agrega el choclo y cocina hasta obtener una pasta cremosa.","Perfuma con albahaca, pimentón, sal y pimienta; añade queso si quieres.","Arma paquetes con dos chalas encontradas, rellena y ata con tiras de chala.","Cocina al vapor o en agua apenas hirviendo 30–40 minutos y sirve tibias."],ilu:{t:"envuelto",c:["#9DBE6E","#EFC94C","#5C8A4E"]}},
{id:"ar-08",pais:"Argentina",nombre:"Carbonada criolla",desc:"Guiso de carne, zapallo, choclo y duraznos, dulce y salado a la vez, típico del norte.",tiempo:100,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["800 g de carne de res en cubos","1 cebolla","1 morrón","2 tomates","500 g de zapallo en cubos","2 papas","2 batatas","2 choclos en rodajas","100 g de orejones de durazno","1 litro de caldo"],pasos:["Dora la carne en una olla con un poco de aceite y reserva.","En la misma olla rehoga cebolla, morrón y tomate picados.","Vuelve la carne, cubre con caldo y cocina 40 minutos a fuego bajo.","Agrega papa, batata, zapallo y choclo; cocina 20 minutos más.","Suma los orejones, rectifica la sal y cocina hasta que todo esté tierno.","Sirve bien caliente, tradicionalmente dentro de un zapallo ahuecado."],ilu:{t:"bowl",c:["#C9762B","#EFC94C","#DD8436"]}},
{id:"ar-09",pais:"Argentina",nombre:"Alfajores de maicena",desc:"Tapas que se deshacen en la boca, unidas con dulce de leche y bordeadas de coco rallado.",tiempo:75,porciones:12,dificultad:"Media",tipo:["postre"],nivel:3,ingredientes:["300 g de maicena","200 g de harina","200 g de manteca","150 g de azúcar","3 yemas","Ralladura de 1 limón","1 cdita de esencia de vainilla","400 g de dulce de leche repostero","Coco rallado"],pasos:["Bate la manteca con el azúcar hasta cremar; agrega yemas, vainilla y ralladura.","Incorpora maicena y harina tamizadas hasta formar una masa suave; refrigera 30 minutos.","Estira de 5 mm y corta discos; hornea a 170 °C por 10–12 minutos sin que doren.","Deja enfriar por completo (las tapas son muy frágiles).","Une de a pares con abundante dulce de leche y haz rodar los bordes por coco rallado."],ilu:{t:"pan",c:["#F2E3C2","#FFFFFF","#C98B2D"]}},
{id:"ar-10",pais:"Argentina",nombre:"Pastelitos criollos",desc:"Hojaldres rellenos de dulce de membrillo, fritos y bañados en almíbar, clásicos del 25 de Mayo.",tiempo:80,porciones:8,dificultad:"Media",tipo:["postre"],nivel:3,ingredientes:["500 g de harina","100 g de grasa o manteca (más extra para hojaldrar)","Agua con sal cantidad necesaria","300 g de dulce de membrillo","Grasa o aceite para freír","200 g de azúcar para el almíbar","Granas de colores (opcional)"],pasos:["Forma una masa lisa con harina, grasa y agua con sal; deja descansar 20 minutos.","Estira fino, unta con grasa, dobla en capas y repite dos veces para hojaldrar.","Corta cuadrados, coloca un cubo de membrillo y cierra con otro cuadrado girado, uniendo las puntas.","Fríe primero en grasa tibia para abrir el hojaldre y luego en caliente para dorar.","Baña con almíbar liviano y decora con granas antes de servir."],ilu:{t:"pan",c:["#E8C36A","#C0392B","#F2E3C2"]}},
{id:"bo-01",pais:"Bolivia",nombre:"Salteñas",desc:"Empanadas horneadas de masa dulce con relleno jugoso de carne y caldo gelatinizado.",tiempo:180,porciones:8,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["500 g de harina","100 g de manteca","2 cdas de azúcar","1 cdita de achiote molido","400 g de pollo o carne de res cocida y desmenuzada","2 papas cocidas en cubos","1/2 taza de arvejas","1 cebolla picada","2 cdas de ají amarillo molido","2 tazas de caldo con 1 cda de gelatina sin sabor","Huevo duro y aceitunas"],pasos:["Prepara el jigote: rehoga cebolla con ají y achiote, agrega carne, papa, arvejas y el caldo con gelatina; enfría hasta que cuaje.","Haz la masa con harina, manteca, azúcar, achiote y agua tibia; deja reposar.","Estira discos de masa y rellena con el jigote frío, un trozo de huevo y aceituna.","Cierra con repulgue hacia arriba, formando la cresta característica.","Hornea a 250 °C por 12–15 minutos hasta que brillen.","Sirve calientes y cómelas de pie: el caldo interior es traicionero."],ilu:{t:"empanada",c:["#DD8436","#B0532F","#8C4A32"]}},
{id:"bo-02",pais:"Bolivia",nombre:"Pique macho",desc:"Montaña de carne, salchicha y papas fritas con cebolla, tomate y locoto: plato para compartir.",tiempo:60,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["500 g de lomo de res en cubos","2 salchichas en rodajas","4 papas grandes para freír","1 cebolla en pluma","2 tomates en gajos","1 locoto en tiras","2 huevos duros","2 cdas de mostaza","2 cdas de kétchup","Salsa de soya y cerveza negra (un chorro)"],pasos:["Fríe las papas en bastones gruesos y resérvalas calientes.","Saltea la carne a fuego fuerte hasta dorar; agrega la salchicha.","Suma cebolla, tomate y locoto; saltea 3 minutos para que queden crocantes.","Sazona con mostaza, kétchup, soya y un chorro de cerveza; deja reducir.","Sirve la mezcla sobre las papas y corona con huevo duro en rodajas."],ilu:{t:"plato",c:["#8C4A32","#E3B23C","#C0392B"]}},
{id:"bo-03",pais:"Bolivia",nombre:"Silpancho",desc:"Carne apanada extendida y delgada sobre arroz y papas, coronada con huevo frito y sarsa.",tiempo:50,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["4 filetes de res","2 tazas de pan molido","2 tazas de arroz cocido","4 papas cocidas en rodajas","4 huevos","1 cebolla picada fina","2 tomates picados","1 locoto picado (opcional)","Vinagre, sal y pimienta","Aceite para freír"],pasos:["Apana los filetes con pan molido y mártalos hasta dejarlos muy delgados y grandes.","Fríe las rodajas de papa hasta dorar y reserva.","Fríe los silpanchos 1–2 minutos por lado en aceite caliente.","Prepara la sarsa mezclando cebolla, tomate y locoto con vinagre y sal.","Sirve sobre una cama de arroz y papas, con huevo frito y sarsa encima."],ilu:{t:"plato",c:["#D9A05B","#EFC94C","#C0392B"]}},
{id:"bo-04",pais:"Bolivia",nombre:"Sopa de maní",desc:"Sopa cremosa de maní molido con carne y papas fritas por encima, orgullo cochabambino.",tiempo:90,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 taza de maní crudo pelado","500 g de carne de res con hueso","2 papas en bastones","1/2 taza de arvejas","1 zanahoria picada","1 cebolla picada","1/2 taza de fideo (opcional)","Orégano y comino","Perejil picado","Aceite para freír"],pasos:["Licúa el maní con un poco de agua hasta obtener una crema.","Hierve la carne con cebolla y zanahoria durante 40 minutos para hacer un caldo.","Agrega el maní licuado y cocina a fuego bajo 30 minutos, revolviendo para que no se pegue.","Suma arvejas y fideo, y cocina hasta que estén tiernos; sazona con orégano y comino.","Fríe los bastones de papa y colócalos encima de cada plato con perejil al servir."],ilu:{t:"bowl",c:["#E8C36A","#D9A05B","#5C8A4E"]}},
{id:"bo-05",pais:"Bolivia",nombre:"Chairo paceño",desc:"Sopa andina contundente de chuño, carne y mote, ideal para el frío del altiplano.",tiempo:120,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 taza de chuño remojado y martajado","400 g de carne de res","200 g de carne de cordero","1 taza de mote de maíz cocido","2 papas en cubos","1 zanahoria","1/2 taza de habas","1 cebolla","1 ramita de hierbabuena","Orégano y sal"],pasos:["Hierve las carnes en abundante agua con cebolla durante 45 minutos.","Agrega el chuño martajado y cocina 20 minutos.","Suma papa, zanahoria, habas y mote; cocina hasta que todo esté tierno.","Sazona con orégano y sal, y perfuma con hierbabuena al final.","Sirve bien caliente con la carne en trozos en cada plato."],ilu:{t:"bowl",c:["#C9A36A","#8C6A4A","#5C8A4E"]}},
{id:"bo-06",pais:"Bolivia",nombre:"Fricasé paceño",desc:"Caldo picante de cerdo con ají amarillo, mote y chuño, famoso por revivir a cualquiera.",tiempo:150,porciones:6,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["1 kg de cerdo en trozos (costilla y carne)","4 cdas de ají amarillo molido","4 dientes de ajo","1 cdita de comino","1 cdita de orégano","1/2 taza de pan molido","2 tazas de mote cocido","6 chuños cocidos","Cebolla verde picada","Sal y pimienta"],pasos:["Sofríe el ají amarillo con ajo, comino y orégano en un poco de aceite.","Agrega el cerdo, cubre con agua caliente y cocina a fuego bajo 1,5 a 2 horas hasta que esté muy tierno.","Espesa ligeramente el caldo con pan molido disuelto, revolviendo.","Rectifica la sal: el caldo debe quedar picante y sustancioso.","Sirve cada plato con mote, chuño y cebolla verde por encima."],ilu:{t:"bowl",c:["#E3A23B","#F2E3C2","#5C8A4E"]}},
{id:"bo-07",pais:"Bolivia",nombre:"Majadito cruceño",desc:"Arroz colorado con charque deshilachado, plátano frito y huevo, emblema del oriente boliviano.",tiempo:70,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["300 g de charque (carne seca) o falda","2 tazas de arroz","1 cebolla picada","1 tomate picado","1 pimentón picado","1 cdita de urucú (achiote)","2 plátanos maduros","4 huevos","Yuca cocida (opcional)","Sal"],pasos:["Hierve el charque para desalar, luego deshiláchalo y dóralo en sartén.","Sofríe cebolla, tomate y pimentón con el urucú disuelto en aceite.","Agrega el arroz y el charque, cubre con agua caliente y cocina hasta que el arroz esté a punto.","Fríe los plátanos en rodajas y los huevos.","Sirve el majadito con plátano frito y huevo encima de cada porción."],ilu:{t:"plato",c:["#D98436","#8C4A32","#EFC94C"]}},
{id:"bo-08",pais:"Bolivia",nombre:"Sajta de pollo",desc:"Pollo bañado en salsa de ají amarillo servido con papa, chuño y sarsa de cebolla.",tiempo:80,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["4 presas de pollo","4 cdas de ají amarillo molido","1 cebolla picada","2 dientes de ajo","1 cdita de comino y orégano","4 papas cocidas","4 chuños cocidos (chuño phuti)","1 cebolla en pluma con tomate para la sarsa","Perejil picado","Sal"],pasos:["Cuece el pollo en agua con sal hasta que esté tierno; reserva el caldo.","Sofríe el ají amarillo con cebolla, ajo, comino y orégano.","Agrega caldo y el pollo, y cocina 15 minutos para que la salsa tome cuerpo.","Prepara la sarsa cruda con cebolla, tomate, sal y un toque de vinagre.","Sirve el pollo con su salsa, papa, chuño y la sarsa por encima."],ilu:{t:"plato",c:["#E3A23B","#F2E3C2","#C0392B"]}},
{id:"bo-09",pais:"Bolivia",nombre:"Cuñapés",desc:"Panecillos de almidón de yuca y queso, crocantes por fuera y elásticos por dentro.",tiempo:40,porciones:6,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["2 tazas de almidón de yuca","2 tazas de queso semiduro rallado","1 huevo","2 cdas de mantequilla","Leche cantidad necesaria","1 pizca de sal"],pasos:["Mezcla el almidón con el queso, la sal, el huevo y la mantequilla.","Agrega leche de a poco hasta lograr una masa suave que no se pegue.","Forma bolitas del tamaño de una nuez grande.","Hornea a 200 °C por 15–18 minutos hasta que doren apenas.","Sírvelos tibios, idealmente con un café o un api."],ilu:{t:"pan",c:["#E8C36A","#FFF6E3","#C98B2D"]}},
{id:"bo-10",pais:"Bolivia",nombre:"Api morado con pastel",desc:"Bebida caliente y espesa de maíz morado con canela, acompañada de pastel de queso frito.",tiempo:45,porciones:4,dificultad:"Fácil",tipo:["bebida"],nivel:2,ingredientes:["1 taza de harina de maíz morado","6 tazas de agua","1 rama de canela","3 clavos de olor","Azúcar al gusto","Jugo de 1 limón","4 láminas de masa de empanada grande","150 g de queso fresco","Aceite para freír","Azúcar impalpable"],pasos:["Disuelve la harina de maíz morado en agua fría.","Hierve con canela y clavo, revolviendo 20 minutos hasta espesar.","Endulza y agrega el jugo de limón para avivar el color.","Rellena las láminas de masa con queso, cierra y fríe hasta inflar y dorar.","Espolvorea el pastel con azúcar impalpable y sirve junto al api bien caliente."],ilu:{t:"taza",c:["#6E4585","#F2E3C2","#FFF6E3"]}},
{id:"br-01",pais:"Brasil",nombre:"Feijoada",desc:"El guiso nacional brasileño: frijoles negros con carnes de cerdo, servido con arroz, farofa y naranja.",tiempo:180,porciones:8,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["500 g de frijoles negros (remojados)","300 g de costilla de cerdo salada (desalada)","200 g de tocino","2 chorizos paio o ahumados","300 g de carne seca (desalada)","1 cebolla","4 dientes de ajo","2 hojas de laurel","Arroz blanco, farofa y col salteada para acompañar","2 naranjas en gajos"],pasos:["Desala las carnes desde la víspera cambiando el agua varias veces.","Cocina los frijoles con laurel en abundante agua durante 1 hora.","Agrega las carnes en trozos y cocina 1 hora más a fuego bajo.","Sofríe cebolla y ajo, incorpora un cucharón de frijoles machacados y devuelve todo a la olla para espesar.","Cocina hasta que el caldo esté denso y las carnes muy tiernas.","Sirve con arroz, farofa, col y naranja, que aligera el plato."],ilu:{t:"bowl",c:["#3A2E2A","#8C4A32","#DD8436"]}},
{id:"br-02",pais:"Brasil",nombre:"Moqueca baiana",desc:"Pescado cocido en leche de coco, aceite de dendê y pimentones, servido burbujeante en cazuela.",tiempo:60,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["800 g de pescado blanco firme en postas","Jugo de 2 limones","3 dientes de ajo","1 cebolla en aros","1 pimentón rojo y 1 verde en aros","2 tomates en rodajas","400 ml de leche de coco","2 cdas de aceite de dendê","Cilantro fresco","Sal y pimienta"],pasos:["Marina el pescado con limón, ajo, sal y pimienta por 30 minutos.","En una cazuela acomoda capas de cebolla, pimentón y tomate, y el pescado encima.","Vierte la leche de coco y cocina tapado a fuego medio 15 minutos sin revolver.","Agrega el aceite de dendê y cocina 5 minutos más.","Termina con abundante cilantro y sirve con arroz blanco o pirão."],ilu:{t:"pescado",c:["#E0863B","#C95B39","#5C8A4E"]}},
{id:"br-03",pais:"Brasil",nombre:"Pão de queijo",desc:"Panecillos de almidón de yuca y queso, dorados por fuera y chiclosos por dentro.",tiempo:50,porciones:6,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["500 g de polvilho (almidón de yuca agrio o dulce)","250 ml de leche","100 ml de aceite","2 huevos","250 g de queso semicurado rallado","1 cdita de sal"],pasos:["Hierve la leche con el aceite y la sal.","Vierte sobre el polvilho y mezcla hasta escaldar la masa; deja entibiar.","Incorpora los huevos uno a uno y luego el queso, amasando hasta integrar.","Forma bolitas con las manos aceitadas.","Hornea a 180 °C por 20–25 minutos hasta que doren; sírvelos calientes."],ilu:{t:"pan",c:["#E8C36A","#FFF6E3","#D9A05B"]}},
{id:"br-04",pais:"Brasil",nombre:"Coxinha",desc:"Croqueta en forma de gota rellena de pollo cremoso, empanizada y frita: reina de los botecos.",tiempo:90,porciones:8,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["2 pechugas de pollo","1 litro de caldo de pollo","500 g de harina de trigo","2 cdas de mantequilla","1 cebolla picada","2 dientes de ajo","100 g de queso crema (opcional)","2 huevos batidos","Pan molido","Aceite para freír"],pasos:["Cuece el pollo en el caldo, desmenúzalo y saltéalo con cebolla y ajo; mezcla con queso crema.","Hierve el caldo con mantequilla y agrega la harina de golpe, revolviendo hasta formar una masa lisa.","Deja entibiar la masa y amásala hasta que quede suave.","Toma porciones, rellena con el pollo y forma gotas cerrando hacia la punta.","Pasa por huevo y pan molido, y fríe en aceite caliente hasta dorar."],ilu:{t:"empanada",c:["#C98B2D","#A66A1F","#F2E3C2"]}},
{id:"br-05",pais:"Brasil",nombre:"Brigadeiros",desc:"Bolitas de chocolate y leche condensada cubiertas de granas, infaltables en todo cumpleaños.",tiempo:30,porciones:10,dificultad:"Fácil",tipo:["postre"],nivel:1,ingredientes:["1 lata de leche condensada","3 cdas de cacao en polvo","1 cda de mantequilla","Granas de chocolate para cubrir"],pasos:["Mezcla la leche condensada, el cacao y la mantequilla en una olla.","Cocina a fuego bajo revolviendo siempre hasta que la mezcla se despegue del fondo (8–10 minutos).","Vierte en un plato engrasado y deja enfriar por completo.","Con las manos enmantequilladas forma bolitas.","Ruédalas por las granas y sírvelas en pirotines."],ilu:{t:"pan",c:["#5A3A2A","#3A2419","#8C5A3A"]}},
{id:"br-06",pais:"Brasil",nombre:"Acarajé",desc:"Buñuelo de frijol de ojo frito en dendê y relleno de vatapá y camarones, símbolo de Bahía.",tiempo:120,porciones:8,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["500 g de frijol de ojo (caupí) remojado y pelado","1 cebolla","Sal","Aceite de dendê abundante para freír","Vatapá para rellenar","200 g de camarones secos o salteados","Ensalada de tomate y cilantro","Pimienta malagueta (opcional)"],pasos:["Frota los frijoles remojados para quitarles la piel por completo.","Procésalos con cebolla y sal hasta obtener una masa aireada; bátela para incorporar aire.","Calienta el dendê y fríe porciones de masa con forma ovalada hasta dorar.","Abre cada acarajé al medio como un pan.","Rellena con vatapá, camarones, ensalada y, si te atreves, malagueta."],ilu:{t:"arepa",c:["#C9692B","#E3A23B","#5C8A4E"]}},
{id:"br-07",pais:"Brasil",nombre:"Vatapá",desc:"Crema bahiana de pan, leche de coco, maní y camarón seco, perfumada con jengibre y dendê.",tiempo:60,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["4 panes del día anterior","400 ml de leche de coco","100 g de maní tostado","100 g de castañas de cajú (opcional)","150 g de camarón seco","1 cebolla","2 dientes de ajo","1 trozo de jengibre","3 cdas de aceite de dendê","Sal"],pasos:["Remoja el pan en la leche de coco hasta ablandar.","Licúa el pan con maní, castañas, camarón seco, cebolla, ajo y jengibre.","Vierte en una olla y cocina a fuego bajo revolviendo siempre.","Agrega el dendê y cocina hasta obtener una crema espesa y brillante.","Sirve caliente como acompañamiento de acarajé, arroz o pescados."],ilu:{t:"bowl",c:["#E0863B","#C9692B","#5C8A4E"]}},
{id:"br-08",pais:"Brasil",nombre:"Picanha asada",desc:"El corte más querido de Brasil, asado con su capa de grasa y apenas sal gruesa.",tiempo:50,porciones:6,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["1 picanha entera (1,2 kg aprox.) con su grasa","Sal gruesa","Farofa, arroz y vinagreta para acompañar"],pasos:["Corta la picanha en bifes gruesos siguiendo la fibra, manteniendo la grasa.","Sala generosamente con sal gruesa justo antes de asar.","Lleva a parrilla bien caliente con la grasa hacia arriba primero.","Sella ambos lados y termina la cocción a fuego medio al punto deseado.","Deja reposar 5 minutos, corta en láminas y sirve con farofa y vinagreta."],ilu:{t:"plato",c:["#8C4A32","#E8C36A","#5C8A4E"]}},
{id:"br-09",pais:"Brasil",nombre:"Caipirinha",desc:"El cóctel brasileño universal: cachaça, lima, azúcar y mucho hielo.",tiempo:10,porciones:2,dificultad:"Fácil",tipo:["bebida"],nivel:1,ingredientes:["2 limas","4 cditas de azúcar","100 ml de cachaça","Hielo en cubos abundante"],pasos:["Corta las limas en octavos quitando el corazón blanco para que no amargue.","Macera la lima con el azúcar en el vaso, presionando para extraer el jugo.","Llena el vaso con hielo.","Agrega la cachaça y revuelve bien de abajo hacia arriba.","Sirve de inmediato con una rodaja de lima."],ilu:{t:"vaso",c:["#CBD98A","#F2F7E3","#5C8A4E"]}},
{id:"br-10",pais:"Brasil",nombre:"Açaí en bowl",desc:"Pulpa helada de açaí batida con banana y servida con granola y fruta fresca.",tiempo:15,porciones:2,dificultad:"Fácil",tipo:["postre"],nivel:2,ingredientes:["400 g de pulpa de açaí congelada","1 banana congelada","2 cdas de miel o jarabe de guaraná","1/2 taza de granola","Banana y frutillas en rodajas para decorar","Coco rallado (opcional)"],pasos:["Deja la pulpa de açaí 5 minutos fuera del congelador para que ceda apenas.","Licúa el açaí con la banana congelada y la miel hasta lograr una crema espesa.","Sirve de inmediato en bowls fríos.","Cubre con granola, fruta fresca y coco rallado.","Cómelo con cuchara antes de que se derrita."],ilu:{t:"bowl",c:["#6E4585","#EFC94C","#D98A8A"]}},
{id:"cl-01",foto:"img/pastel-choclo.jpg",pais:"Chile",nombre:"Pastel de choclo",desc:"Pino de carne, pollo, huevo y aceitunas bajo una capa dorada de choclo con albahaca, horneado en greda.",tiempo:100,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["8 choclos (o 1 kg de granos)","Hojas de albahaca","1/2 taza de leche","500 g de carne molida o picada","2 cebollas picadas","1 cdita de comino y 1 de ají de color","2 presas de pollo cocidas","3 huevos duros","12 aceitunas negras","Pasas y azúcar para espolvorear"],pasos:["Prepara el pino: sofríe la cebolla, agrega la carne, comino, ají de color y sal; cocina 15 minutos.","Muele el choclo con albahaca, cocínalo con leche y una pizca de sal revolviendo hasta espesar.","En fuentes de greda pon el pino, trozos de pollo, huevo duro, aceitunas y pasas.","Cubre con la pasta de choclo y espolvorea azúcar por encima.","Hornea a 200 °C por 30 minutos hasta que la superficie dore y burbujee.","Sirve bien caliente en la misma fuente."],ilu:{t:"pastel",c:["#EFC94C","#B5482F","#C98B2D"]}},
{id:"cl-02",foto:"img/empanada-pino.jpg",pais:"Chile",nombre:"Empanadas de pino",desc:"Empanadas horneadas de masa suave rellenas de pino de carne, cebolla, huevo, aceituna y pasas.",tiempo:90,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["500 g de harina","100 g de manteca o margarina derretida","Salmuera tibia (agua, sal)","500 g de carne molida o picada","3 cebollas picadas","1 cdita de comino","1 cda de ají de color","2 huevos duros","12 aceitunas negras","Pasas y 1 huevo para pintar"],pasos:["Haz el pino el día anterior: sofríe cebolla, agrega carne y aliños, cocina y deja reposar para que jugoso.","Prepara la masa con harina, manteca y salmuera tibia; amasa hasta que quede lisa.","Estira discos, rellena con pino, un trozo de huevo, aceituna y pasas.","Cierra en forma rectangular doblando las puntas, el sello clásico chileno.","Pinta con huevo y hornea a 220 °C por 20–25 minutos hasta dorar."],ilu:{t:"empanada",c:["#E3B23C","#C98B2D","#3A2E2A"]}},
{id:"cl-03",foto:"img/cazuela.jpg",pais:"Chile",nombre:"Cazuela de vacuno",desc:"Caldo reconfortante con carne, papa, zapallo, choclo y porotos verdes, servido humeante.",tiempo:90,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["6 trozos de osobuco o tapapecho","6 papas peladas","6 trozos de zapallo","2 choclos en rodajas","1 taza de porotos verdes","1/2 taza de arroz","1 cebolla","1 zanahoria","Orégano, comino y sal","Cilantro picado"],pasos:["Dora la carne en la olla y agrega cebolla y zanahoria picadas.","Cubre con agua caliente y cocina 50 minutos a fuego medio espumando el caldo.","Agrega papas, zapallo y choclo; cocina 15 minutos.","Suma el arroz y los porotos verdes y cocina 15 minutos más.","Rectifica los aliños y sirve cada plato con un trozo de cada ingrediente y cilantro fresco."],ilu:{t:"bowl",c:["#E3A23B","#EFC94C","#5C8A4E"]}},
{id:"cl-04",foto:"img/porotos-granados.jpg",pais:"Chile",nombre:"Porotos granados",desc:"Porotos frescos cocidos con mazamorra de choclo, zapallo y albahaca: el sabor del verano chileno.",tiempo:75,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 kg de porotos granados desgranados","500 g de zapallo en cubos","4 choclos rallados o molidos","1 cebolla picada","2 dientes de ajo","1 cda de ají de color","Hojas de albahaca","Sal y pimienta","Pebre o ensalada chilena para acompañar"],pasos:["Cuece los porotos con el zapallo en agua hasta que estén tiernos (40 minutos).","Sofríe cebolla y ajo con ají de color y agrégalos a la olla.","Incorpora el choclo molido con albahaca y cocina 15 minutos revolviendo: la mazamorra espesa el guiso.","Aplasta parte del zapallo para dar cremosidad y rectifica la sal.","Sirve caliente con pebre o ensalada a la chilena."],ilu:{t:"bowl",c:["#D9C28A","#EFC94C","#5C8A4E"]}},
{id:"cl-05",foto:"img/charquicán.jpg",pais:"Chile",nombre:"Charquicán",desc:"Guiso casero de papas y zapallo machacados con carne y verduras, coronado con huevo frito.",tiempo:60,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["400 g de posta molida o charqui desmenuzado","4 papas en cubos","400 g de zapallo en cubos","1 taza de porotos verdes picados","1 choclo desgranado","1 cebolla picada","1 cdita de comino y ají de color","4 huevos","Sal y pimienta"],pasos:["Sofríe la cebolla con los aliños y dora la carne.","Agrega papas y zapallo, cubre apenas con agua y cocina 20 minutos.","Suma porotos verdes y choclo, y cocina hasta que todo esté tierno.","Machaca groseramente con cuchara de palo: debe quedar cremoso pero con trozos.","Sirve con un huevo frito encima de cada plato."],ilu:{t:"plato",c:["#E0A53B","#5C8A4E","#EFC94C"]}},
{id:"cl-06",foto:"img/completo-italiano.jpg",pais:"Chile",nombre:"Completo italiano",desc:"La versión chilena del hot dog: vienesa con tomate, palta y mayonesa, los colores de Italia.",tiempo:25,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:1,ingredientes:["4 panes de completo","4 vienesas","2 tomates en cubitos","2 paltas maduras molidas","Mayonesa abundante","Sal"],pasos:["Calienta las vienesas en agua caliente sin hervir para que no revienten.","Entibia los panes al vapor o en horno suave.","Muele la palta con una pizca de sal.","Arma: vienesa, tomate, palta y un cordón generoso de mayonesa.","Sirve de inmediato, con servilletas a mano."],ilu:{t:"sandwich",c:["#E8C36A","#9DBE6E","#C0392B"]}},
{id:"cl-07",foto:"img/sopaipillas.jpg",pais:"Chile",nombre:"Sopaipillas",desc:"Discos fritos de masa con zapallo, perfectos para la lluvia, con pebre o pasadas en chancaca.",tiempo:45,porciones:6,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["500 g de harina","250 g de zapallo camote cocido y molido","60 g de manteca derretida","1 cdita de sal","Aceite para freír","Para pasarlas: 1 pan de chancaca, cáscara de naranja y canela (opcional)"],pasos:["Mezcla la harina con el zapallo molido, la manteca y la sal hasta formar una masa suave.","Estira de 5 mm, corta discos y pínchalos con un tenedor.","Fríe en aceite caliente hasta que se inflen y doren por ambos lados.","Para la versión dulce, hierve la chancaca con naranja y canela y baña las sopaipillas.","Sírvelas calientes con pebre si las prefieres saladas."],ilu:{t:"pan",c:["#E0A53B","#C98B2D","#F2E3C2"]}},
{id:"cl-08",foto:"img/chorrillana.jpg",pais:"Chile",nombre:"Chorrillana",desc:"Papas fritas cubiertas de carne salteada, cebolla dorada y huevos: nacida en Valparaíso para compartir.",tiempo:50,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 kg de papas en bastones","500 g de lomo o posta en tiras","2 cebollas en pluma","4 huevos","2 vienesas o longaniza en rodajas (opcional)","Aceite para freír","Sal, pimienta y comino"],pasos:["Fríe las papas hasta dorar y mantenlas calientes en la fuente.","Saltea la carne a fuego fuerte con sal, pimienta y comino.","Dora la cebolla en la misma sartén hasta que caramelice.","Agrega los huevos revueltos a la sartén y mezcla apenas con carne y cebolla.","Vuelca todo sobre las papas y lleva la fuente al centro de la mesa."],ilu:{t:"plato",c:["#E8C36A","#8C4A32","#EFC94C"]}},
{id:"cl-09",foto:"img/pulmay.jpg",pais:"Chile",nombre:"Pulmay (curanto en olla)",desc:"Mariscos, carnes y papas cocidos al vapor en capas, la versión casera del curanto chilote.",tiempo:120,porciones:8,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["1 kg de choritos","1 kg de almejas","4 longanizas","4 presas de pollo","500 g de costillar de cerdo ahumado","8 papas","2 cebollas en cuartos","1 taza de vino blanco","Hojas de repollo","Ají de color y orégano"],pasos:["En una olla grande pon una cama de cebolla y las carnes sazonadas.","Agrega las papas y cubre con hojas de repollo.","Suma los mariscos bien lavados encima y vierte el vino blanco.","Tapa con más hojas de repollo y cocina a fuego medio 50–60 minutos sin destapar.","Sirve por capas con el caldito que se forma en pocillos aparte."],ilu:{t:"bowl",c:["#C9692B","#3A2E2A","#9DBE6E"]}},
{id:"cl-10",foto:"img/mote-con-huesillo.jpg",pais:"Chile",nombre:"Mote con huesillo",desc:"Refresco tradicional de duraznos deshidratados con mote de trigo, infaltable en verano.",tiempo:60,porciones:6,dificultad:"Fácil",tipo:["bebida","postre"],nivel:2,ingredientes:["300 g de huesillos (duraznos secos) remojados desde la víspera","1 taza de azúcar o 1/2 pan de chancaca","1 rama de canela","2 tazas de mote de trigo cocido","Agua"],pasos:["Hierve los huesillos en su agua de remojo con azúcar y canela por 30 minutos.","Deja enfriar el jugo: debe quedar dulce y de color ámbar.","Refrigera hasta que esté bien helado.","Pon 2–3 cucharadas de mote en cada vaso.","Agrega un huesillo y completa con el jugo frío; se toma y se come con cuchara."],ilu:{t:"vaso",c:["#E0863B","#E8C36A","#C9692B"]}},
{id:"co-01",pais:"Colombia",nombre:"Bandeja paisa",desc:"El plato montañero por excelencia: frijoles, arroz, carnes, huevo, chicharrón, arepa y aguacate.",tiempo:120,porciones:4,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["2 tazas de frijoles cargamanto (remojados)","2 tazas de arroz blanco cocido","400 g de carne molida","400 g de tocino para chicharrón","4 chorizos","4 huevos","2 plátanos maduros","4 arepas","1 aguacate","Hogao (tomate y cebolla larga sofritos)"],pasos:["Cocina los frijoles con un trozo de tocino hasta que estén tiernos y el caldo espese; termina con hogao.","Sofríe la carne molida con sal, comino y hogao.","Corta el tocino, cocínalo en agua y luego fríelo en su grasa hasta que truene: ese es el chicharrón.","Fríe los chorizos, las tajadas de maduro y los huevos.","Arma la bandeja: frijoles, arroz, carne, chicharrón, chorizo, huevo, tajadas, arepa y aguacate."],ilu:{t:"plato",c:["#8C4A32","#EFC94C","#9DBE6E"]}},
{id:"co-02",pais:"Colombia",nombre:"Ajiaco santafereño",desc:"Sopa bogotana de tres papas y pollo perfumada con guascas, servida con crema, alcaparras y mazorca.",tiempo:110,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["2 pechugas de pollo","500 g de papa criolla","500 g de papa pastusa","500 g de papa sabanera","3 mazorcas en trozos","1 manojo de guascas","2 dientes de ajo","1 cebolla larga","Crema de leche y alcaparras para servir","Aguacate"],pasos:["Cocina el pollo con cebolla, ajo y sal en 2,5 litros de agua; retira y desmenuza.","En el caldo cocina las papas pastusa y sabanera en rodajas hasta que empiecen a deshacerse.","Agrega la papa criolla y la mazorca; la criolla se disuelve y da el espesor típico.","Suma las guascas en los últimos 10 minutos.","Sirve con pollo desmenuzado, crema, alcaparras y aguacate aparte."],ilu:{t:"bowl",c:["#E8C36A","#EFC94C","#5C8A4E"]}},
{id:"co-03",pais:"Colombia",nombre:"Sancocho de gallina",desc:"Caldo sustancioso de gallina con yuca, plátano, papa y mazorca, plato de domingo y de río.",tiempo:150,porciones:8,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 gallina o pollo grande en presas","500 g de yuca en trozos","2 plátanos verdes en trozos","6 papas","3 mazorcas","1 cebolla larga","2 tomates","2 dientes de ajo","Cilantro y comino","Sal"],pasos:["Haz un guiso con cebolla, tomate y ajo, y dora las presas de gallina.","Cubre con 3 litros de agua y cocina 1 hora (la gallina pide tiempo).","Agrega plátano y yuca y cocina 25 minutos.","Suma papa y mazorca y cocina hasta que todo esté tierno.","Sazona con comino y sal, y termina con cilantro fresco; sirve con arroz y aguacate."],ilu:{t:"bowl",c:["#E3A23B","#EFC94C","#5C8A4E"]}},
{id:"co-04",pais:"Colombia",nombre:"Arepas de queso",desc:"Arepas de maíz rellenas y cubiertas de queso, doradas en budare o sartén.",tiempo:35,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["2 tazas de harina de maíz precocida","2,5 tazas de agua tibia","1,5 tazas de queso costeño o campesino rallado","2 cdas de mantequilla","1 cdita de sal"],pasos:["Mezcla la harina con agua, sal, mantequilla y la mitad del queso; amasa hasta que quede suave.","Deja reposar 5 minutos para que hidrate.","Forma bolas, rellena con el queso restante y aplana en discos de 1 cm.","Asa en sartén o budare a fuego medio 5–7 minutos por lado hasta dorar.","Sirve calientes con mantequilla por encima."],ilu:{t:"arepa",c:["#F2E3C2","#FFF6E3","#E8C36A"]}},
{id:"co-05",pais:"Colombia",nombre:"Tamales tolimenses",desc:"Masa de maíz y arroz con pollo, cerdo y verduras, envuelta en hoja de plátano y cocida por horas.",tiempo:240,porciones:10,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["3 tazas de masa de maíz peto cocido y molido","1 taza de arroz semicocido","500 g de costilla de cerdo","500 g de pollo en presas","1 taza de arvejas","2 zanahorias en rodajas","4 huevos duros","Hogao abundante","Hojas de plátano soasadas","Comino, achiote y sal"],pasos:["Adoba las carnes desde la víspera con hogao, comino y achiote.","Mezcla la masa de maíz con el arroz, arvejas y parte del hogao.","Sobre dos hojas de plátano pon una capa de masa, las carnes, zanahoria y huevo.","Cierra formando un atado firme y amarra con cabuya.","Cocina los tamales en agua hirviendo con sal durante 2,5 a 3 horas.","Sirve con chocolate caliente, como manda la tradición."],ilu:{t:"envuelto",c:["#5C7A3E","#EFC94C","#8C6A4A"]}},
{id:"co-06",pais:"Colombia",nombre:"Patacones con hogao",desc:"Plátano verde frito dos veces hasta quedar crocante, servido con hogao de tomate y cebolla.",tiempo:40,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["3 plátanos verdes","Aceite para freír","Sal","Para el hogao: 3 tomates maduros picados","4 tallos de cebolla larga picada","1 diente de ajo","Comino y sal"],pasos:["Corta los plátanos en trozos de 4 cm y fríelos 3 minutos sin dorar del todo.","Aplástalos con una pataconera o entre dos tablas.","Fríelos de nuevo en aceite bien caliente hasta que queden dorados y crocantes; sala al salir.","Para el hogao, sofríe cebolla, ajo y tomate a fuego bajo hasta formar una salsa.","Sirve los patacones calientes con el hogao por encima o aparte."],ilu:{t:"plato",c:["#E0A53B","#C0392B","#5C8A4E"]}},
{id:"co-07",pais:"Colombia",nombre:"Changua",desc:"Sopa bogotana de leche con huevo pochado, cilantro y pan calado: desayuno de tierra fría.",tiempo:20,porciones:2,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["2 tazas de leche","2 tazas de agua","2 huevos","2 tallos de cebolla larga picada","Cilantro fresco picado","2 panes tostados o calados","Sal"],pasos:["Hierve la leche con el agua, la cebolla larga y sal.","Baja el fuego y casca los huevos enteros dentro, sin revolver.","Cocina 3–4 minutos hasta que la clara cuaje y la yema quede blanda.","Sirve en tazones con abundante cilantro.","Agrega el pan para que se cale en el caldo."],ilu:{t:"bowl",c:["#F2EDE3","#EFC94C","#5C8A4E"]}},
{id:"co-08",pais:"Colombia",nombre:"Empanadas colombianas",desc:"Empanadas fritas de masa de maíz rellenas de papa y carne, acompañadas de ají picante.",tiempo:90,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["2 tazas de harina de maíz precocida amarilla","2,5 tazas de caldo o agua tibia","300 g de carne de res cocida y picada","3 papas cocidas y machacadas","Hogao","Comino y sal","Aceite para freír","Ají de cilantro: cilantro, cebolla, limón, agua y picante"],pasos:["Prepara el relleno mezclando carne, papa machacada y hogao; sazona con comino.","Forma la masa con la harina, el caldo y sal; debe quedar moldeable.","Toma bolitas, aplánalas sobre plástico, rellena y dobla cerrando en media luna.","Fríe en aceite bien caliente hasta que queden doradas y crujientes.","Sírvelas con ají de cilantro y limón."],ilu:{t:"empanada",c:["#EFC94C","#E0A53B","#8C4A32"]}},
{id:"co-09",pais:"Colombia",nombre:"Arroz con coco",desc:"Arroz caribeño cocido en leche de coco con titoté caramelizado y pasas, dulce y salado.",tiempo:60,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["2 tazas de arroz","4 tazas de leche de coco (primera y segunda extracción)","3 cdas de azúcar o panela rallada","1/2 taza de uvas pasas","Sal"],pasos:["Hierve la primera leche de coco (la más espesa) hasta que el agua se evapore y la grasa se dore: ese es el titoté.","Agrega el azúcar y deja caramelizar apenas.","Suma el arroz, las pasas, la segunda leche de coco y sal.","Cocina destapado hasta que seque, luego tapa y baja el fuego 20 minutos.","Sirve como acompañamiento clásico de pescado frito con patacones."],ilu:{t:"plato",c:["#C9A36A","#8C6A4A","#5A3A2A"]}},
{id:"co-10",pais:"Colombia",nombre:"Buñuelos colombianos",desc:"Bolas doradas de queso costeño y almidón, infaltables en diciembre junto a la natilla.",tiempo:45,porciones:6,dificultad:"Media",tipo:["postre"],nivel:3,ingredientes:["2 tazas de queso costeño rallado","1 taza de almidón de yuca","1/4 taza de fécula de maíz","1 huevo","2 cdas de azúcar","1 cdita de polvo de hornear","Leche si la masa lo pide","Aceite abundante para freír"],pasos:["Mezcla el queso con los almidones, el azúcar y el polvo de hornear.","Agrega el huevo y amasa; si está seca, suma leche por cucharadas.","Forma bolas medianas bien lisas.","Fríe en aceite a fuego medio-bajo: deben girar solas y dorarse parejo sin abrirse.","Escurre sobre papel y sírvelos tibios."],ilu:{t:"pan",c:["#E0A53B","#E8C36A","#C98B2D"]}},
{id:"ec-01",pais:"Ecuador",nombre:"Encebollado",desc:"Sopa costeña de pescado y yuca con cebolla encurtida, célebre por levantar el ánimo.",tiempo:75,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["500 g de albacora o atún fresco","500 g de yuca pelada","2 tomates","1 cebolla colorada en pluma fina","Jugo de 2 limones","Cilantro","1 cdita de comino","2 cdas de achiote en aceite","Chifles o canguil para acompañar","Sal y pimienta"],pasos:["Haz un refrito con tomate, parte de la cebolla, achiote y comino, y cubre con 2 litros de agua.","Cocina el pescado en ese caldo 10 minutos; retíralo y desmenúzalo en trozos grandes.","Cocina la yuca en el mismo caldo hasta que esté suave y córtala en trozos.","Encurte la cebolla restante con limón y sal.","Sirve caldo, yuca y pescado en cada plato, corona con cebolla encurtida y cilantro.","Acompaña con chifles, canguil y más limón."],ilu:{t:"bowl",c:["#E3A23B","#F2E3C2","#B05A8C"]}},
{id:"ec-02",pais:"Ecuador",nombre:"Ceviche de camarón",desc:"Camarones en jugo de limón, naranja y tomate con cebolla y cilantro, al estilo ecuatoriano.",tiempo:40,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["500 g de camarones limpios","Jugo de 4 limones","Jugo de 1 naranja","1/2 taza de salsa de tomate","1 cebolla colorada en pluma encurtida","2 tomates picados","Cilantro picado","1 cda de aceite","Sal y pimienta","Chifles y canguil para servir"],pasos:["Hierve los camarones 2 minutos en agua con sal y enfríalos de inmediato; reserva un poco del agua de cocción.","Mezcla los jugos de limón y naranja con la salsa de tomate y un poco del caldo de camarón.","Agrega camarones, cebolla encurtida, tomate y cilantro.","Sazona con sal, pimienta y el chorrito de aceite; refrigera 20 minutos.","Sirve frío con chifles, canguil y arroz si quieres el combo completo."],ilu:{t:"bowl",c:["#D98A8A","#E0863B","#5C8A4E"]}},
{id:"ec-03",pais:"Ecuador",nombre:"Locro de papa",desc:"Sopa cremosa de papa con queso y aguacate, clásico de la sierra ecuatoriana.",tiempo:50,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["1 kg de papas (mitad en cubos, mitad para deshacer)","1 cebolla blanca picada","2 dientes de ajo","1 cdita de achiote en aceite","1 taza de leche","150 g de queso fresco desmenuzado","1 aguacate","Cilantro","Sal y comino"],pasos:["Sofríe cebolla y ajo con el achiote.","Agrega las papas, cubre con agua y cocina hasta que parte de ellas se deshaga y espese la sopa.","Vierte la leche y cocina 5 minutos más sin que hierva fuerte.","Apaga el fuego e incorpora el queso desmenuzado.","Sirve con aguacate en láminas y cilantro; el ají criollo es bienvenido."],ilu:{t:"bowl",c:["#EFD27A","#F2E3C2","#9DBE6E"]}},
{id:"ec-04",pais:"Ecuador",nombre:"Llapingachos",desc:"Tortillas de papa rellenas de queso, doradas en plancha y servidas con salsa de maní.",tiempo:60,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 kg de papas cocidas","1 cebolla blanca picada fina","2 cdas de achiote en aceite","1 taza de queso fresco desmenuzado","Para la salsa: 1/2 taza de maní tostado licuado con 1 taza de leche","Chorizo, huevo frito y curtido para acompañar","Sal"],pasos:["Aplasta las papas calientes y mézclalas con la cebolla sofrita en achiote y sal.","Deja reposar la masa 30 minutos en frío.","Forma tortillas gruesas rellenas con queso en el centro.","Dóralas en plancha o sartén con poco aceite hasta formar costra por ambos lados.","Cocina el maní licuado con leche y cebolla hasta espesar.","Sirve los llapingachos bañados en salsa de maní con sus acompañamientos."],ilu:{t:"arepa",c:["#E0A53B","#F2E3C2","#C98B2D"]}},
{id:"ec-05",pais:"Ecuador",nombre:"Fanesca",desc:"Sopa ceremonial de Semana Santa con doce granos, zapallo y bacalao en leche.",tiempo:180,porciones:10,dificultad:"Alta",tipo:["comida"],nivel:5,ingredientes:["250 g de bacalao seco (remojado desde la víspera)","1 taza de cada grano: habas, chochos, arvejas, fréjol, maíz tierno, lenteja (y los que sumes hasta doce)","500 g de zapallo y sambo cocidos","2 tazas de leche","1/2 taza de maní licuado con leche","Refrito de cebolla, ajo, comino y achiote","Queso fresco","Empanaditas, maduro frito y huevo duro para decorar"],pasos:["Cocina cada grano por separado hasta que esté tierno (el secreto de la textura).","Haz el refrito y agrega el zapallo y sambo hechos puré con leche.","Incorpora el maní licuado y los granos; cocina a fuego bajo revolviendo.","Cocina el bacalao en leche 10 minutos y agrégalo con su leche a la olla.","Ajusta sal y espesor: debe quedar cremosa y abundante.","Sirve decorada con huevo duro, queso, maduro frito y empanaditas."],ilu:{t:"bowl",c:["#E0C26A","#9DBE6E","#EFC94C"]}},
{id:"ec-06",pais:"Ecuador",nombre:"Bolón de verde",desc:"Bola de plátano verde majado con chicharrón o queso, desayuno de campeones costeños.",tiempo:35,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["4 plátanos verdes","150 g de chicharrón en trozos o queso rallado","2 cdas de mantequilla o aceite con achiote","Sal","Café o jugo para acompañar (huevo frito opcional)"],pasos:["Pela los verdes, córtalos en trozos y fríelos o cocínalos hasta que estén suaves.","Májalos calientes en mortero o tabla hasta formar una masa.","Mezcla con mantequilla, sal y el chicharrón o queso.","Forma bolas compactas con las manos.","Dóralas brevemente en sartén y sírvelas calientes, con huevo frito si el hambre aprieta."],ilu:{t:"pan",c:["#9DA84E","#7A8C3B","#C98B2D"]}},
{id:"ec-07",pais:"Ecuador",nombre:"Seco de chivo",desc:"Estofado de chivo en salsa de naranjilla y cerveza, servido con arroz amarillo y maduro.",tiempo:130,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1,5 kg de carne de chivo o borrego en trozos","1 taza de jugo de naranjilla","1 taza de cerveza o chicha","2 cebollas","2 tomates","1 pimiento","4 dientes de ajo","1 cda de achiote","Cilantro y comino","Arroz amarillo y plátano maduro frito para servir"],pasos:["Licúa cebolla, tomate, pimiento y ajo con la naranjilla y la cerveza.","Sella la carne en una olla con achiote.","Vierte la salsa licuada, sazona con comino y sal, y cocina tapado a fuego bajo 1,5 horas.","Revisa que la carne esté muy suave y la salsa espesa.","Termina con cilantro y sirve con arroz amarillo y maduro frito."],ilu:{t:"plato",c:["#8C5A32","#EFC94C","#5C8A4E"]}},
{id:"ec-08",pais:"Ecuador",nombre:"Encocado de pescado",desc:"Pescado esmeraldeño cocido en salsa de coco con hierbas de monte, puro sabor del Pacífico.",tiempo:50,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["800 g de pescado fresco en trozos","Jugo de 1 limón","400 ml de leche de coco","1 cebolla picada","1 pimiento picado","2 tomates picados","2 dientes de ajo","Chillangua o cilantro","1 cdita de achiote","Arroz y patacones para servir"],pasos:["Adoba el pescado con limón, ajo y sal por 20 minutos.","Haz un refrito con cebolla, pimiento, tomate y achiote.","Agrega la leche de coco y cocina 10 minutos a fuego bajo.","Incorpora el pescado y cocina 10–12 minutos sin revolver bruscamente.","Perfuma con chillangua y sirve con arroz blanco y patacones."],ilu:{t:"pescado",c:["#E0A53B","#C9692B","#5C8A4E"]}},
{id:"ec-09",pais:"Ecuador",nombre:"Fritada",desc:"Cerdo cocido en su propio jugo y dorado en paila de bronce, con mote, maduro y curtido.",tiempo:90,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1,5 kg de carne de cerdo en trozos","1 cabeza de ajo machacada","1 cebolla blanca en trozos","1 cda de comino","2 tazas de agua o cerveza","2 tazas de mote cocido","2 plátanos maduros fritos","Curtido de cebolla y tomate","Papas cocidas (opcional)","Sal"],pasos:["Pon el cerdo en una paila con agua, ajo, cebolla, comino y sal.","Cocina a fuego medio hasta que el agua se evapore.","Sigue cocinando: la carne se dora en su propia grasa, girando los trozos.","Retira cuando esté dorada por fuera y jugosa por dentro.","Sirve con mote, maduro frito, papas y curtido fresco."],ilu:{t:"plato",c:["#B5713A","#F2E3C2","#C0392B"]}},
{id:"ec-10",pais:"Ecuador",nombre:"Empanadas de viento",desc:"Empanadas fritas de queso que se inflan como globos y se espolvorean con azúcar.",tiempo:45,porciones:6,dificultad:"Fácil",tipo:["postre"],nivel:2,ingredientes:["3 tazas de harina","100 g de mantequilla fría","1 huevo","Agua tibia con sal","2 tazas de queso fresco rallado","1/2 cebolla blanca picada fina (opcional)","Aceite abundante para freír","Azúcar para espolvorear"],pasos:["Forma una masa suave con harina, mantequilla, huevo y agua; deja reposar 30 minutos.","Mezcla el queso con la cebolla picada.","Estira discos delgados, rellena y cierra con repulgue torcido.","Fríe en abundante aceite caliente bañando la superficie para que se inflen.","Escurre y espolvorea azúcar antes de servir, todavía calientes."],ilu:{t:"empanada",c:["#E8C36A","#D9A05B","#FFF6E3"]}},
{id:"py-01",pais:"Paraguay",nombre:"Sopa paraguaya",desc:"La única sopa sólida del mundo: torta esponjosa de harina de maíz, queso y cebolla.",tiempo:70,porciones:8,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["3 tazas de harina de maíz","300 g de queso Paraguay o fresco en trozos","2 cebollas picadas","100 g de grasa de cerdo o mantequilla","4 huevos","2 tazas de leche","Sal gruesa"],pasos:["Hierve la cebolla picada con un poco de agua y sal hasta que esté transparente; escurre.","Bate la grasa con los huevos y agrega el queso desmenuzado.","Incorpora la cebolla, la harina de maíz y la leche alternando hasta lograr una mezcla cremosa.","Vierte en una fuente engrasada de unos 4 cm de alto.","Hornea a 200 °C por 40–45 minutos hasta dorar; corta en cuadrados y sirve tibia."],ilu:{t:"pastel",c:["#EFC94C","#C98B2D","#E8C36A"]}},
{id:"py-02",pais:"Paraguay",nombre:"Chipa",desc:"Roscas de almidón de mandioca con queso y anís, el aroma de toda Semana Santa paraguaya.",tiempo:60,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["500 g de almidón de mandioca","250 g de queso Paraguay o semiduro rallado","100 g de grasa de cerdo o mantequilla","3 huevos","1/2 taza de leche","1 cdita de anís en grano","1 cdita de sal"],pasos:["Bate la grasa con los huevos hasta integrar.","Agrega el queso, la sal y el anís.","Incorpora el almidón alternando con la leche hasta formar una masa lisa que no se pegue.","Forma roscas o palitos.","Hornea a 220 °C por 15–20 minutos: doradas por fuera, húmedas por dentro.","Cómelas tibias, como manda el chiperío."],ilu:{t:"pan",c:["#E8C36A","#FFF6E3","#C98B2D"]}},
{id:"py-03",pais:"Paraguay",nombre:"Chipa guazú",desc:"Pastel húmedo de choclo fresco molido con queso y cebolla, primo veraniego de la sopa paraguaya.",tiempo:75,porciones:8,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["8 choclos frescos desgranados","300 g de queso Paraguay o fresco","2 cebollas picadas","100 g de grasa o mantequilla","4 huevos","1 taza de leche","Sal"],pasos:["Muele o procesa los granos de choclo dejando algo de textura.","Sofríe la cebolla en la grasa hasta transparentar.","Mezcla el choclo con huevos, leche, queso en trozos, cebolla y sal.","Vierte en fuente engrasada.","Hornea a 200 °C por 45 minutos hasta que cuaje y dore; sirve como plato o acompañamiento."],ilu:{t:"pastel",c:["#EFD27A","#C98B2D","#EFC94C"]}},
{id:"py-04",pais:"Paraguay",nombre:"Mbeyú",desc:"Torta plana de almidón de mandioca y queso hecha en sartén, crocante y sin gluten.",tiempo:25,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["2 tazas de almidón de mandioca","200 g de queso Paraguay desmenuzado","3 cdas de grasa de cerdo o mantequilla","1/2 taza de leche (aproximado)","Sal"],pasos:["Mezcla el almidón con la grasa frotando con los dedos hasta formar un arenado.","Agrega el queso y la sal, y humedece apenas con leche: debe quedar granulado, no masa.","Calienta una sartén y esparce una capa del granulado presionando con espátula.","Cocina a fuego medio hasta que tome cuerpo y dore; da vuelta como panqueque.","Sirve caliente, ideal con cocido o café con leche."],ilu:{t:"arepa",c:["#F2E3C2","#FFF6E3","#E8C36A"]}},
{id:"py-05",pais:"Paraguay",nombre:"Vorí vorí",desc:"Caldo dorado de gallina con bolitas de harina de maíz y queso flotando como soles.",tiempo:80,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 gallina o pollo en presas","1 cebolla picada","1 tomate picado","1 pimiento (locote) picado","1 cdita de cúrcuma o azafrán del país","1,5 tazas de harina de maíz","100 g de queso Paraguay rallado","2 cdas de grasa","Orégano y sal"],pasos:["Dora las presas con cebolla, tomate y locote, agrega la cúrcuma y cubre con agua.","Cocina 40 minutos hasta tener un caldo sabroso.","Para los vorí: mezcla la harina de maíz con queso, un poco de grasa y caldo caliente hasta poder formar bolitas.","Forma bolitas de 2–3 cm y échalas al caldo hirviendo.","Cocina 10 minutos hasta que floten y estén firmes; sirve bien caliente con orégano."],ilu:{t:"bowl",c:["#E3B23C","#EFD27A","#5C8A4E"]}},
{id:"py-06",pais:"Paraguay",nombre:"So'o yosopy",desc:"Sopa de carne molida fresca con arroz, sencilla y reparadora, de nombre guaraní.",tiempo:50,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["500 g de carne de res molida muy fresca","1 cebolla picada fina","1 locote (pimiento) picado","2 tomates picados","1/2 taza de arroz o fideos finos","2 cdas de aceite","2 litros de agua","Sal (al final) y orégano","Mandioca cocida para acompañar"],pasos:["Sofríe cebolla, locote y tomate en el aceite.","Agrega la carne molida y revuelve deshaciéndola para que no forme grumos.","Vierte el agua fría y cocina 20 minutos a fuego medio.","Suma el arroz y cocina hasta que esté a punto.","Sala recién al final (la tradición dice que si no, se corta) y sirve con mandioca."],ilu:{t:"bowl",c:["#C96A4A","#E3A23B","#5C8A4E"]}},
{id:"py-07",pais:"Paraguay",nombre:"Pira caldo",desc:"Sopa de pescado de río con tomate, locote y un toque de leche, sabor del Paraguay fluvial.",tiempo:60,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 kg de pescado de río (surubí o tararira) en postas","2 cebollas picadas","2 tomates picados","1 locote picado","2 cdas de grasa o aceite","1 taza de leche","100 g de queso Paraguay (opcional)","Comino, laurel y sal","Mandioca cocida"],pasos:["Sofríe cebolla, tomate y locote en la grasa hasta formar una salsa.","Agrega agua caliente, laurel y comino, y deja hervir 10 minutos.","Incorpora las postas de pescado y cocina 15 minutos a fuego suave.","Vierte la leche (y el queso si usas) y calienta sin hervir fuerte.","Sirve caliente con mandioca; cuidado con las espinas y con repetir."],ilu:{t:"bowl",c:["#E0A53B","#F2E3C2","#C0392B"]}},
{id:"py-08",pais:"Paraguay",nombre:"Pastel mandi'o",desc:"Empanada frita de masa de mandioca rellena de so'o ku'i (carne picada), dorada y crocante.",tiempo:90,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 kg de mandioca cocida y molida","1 taza de almidón de mandioca","1 huevo","500 g de carne picada a cuchillo","1 cebolla picada","1 locote picado","Comino, orégano y sal","Aceite o grasa para freír"],pasos:["Prepara el so'o ku'i: sofríe cebolla y locote, agrega la carne y los aliños, y cocina hasta secar.","Amasa la mandioca molida con el almidón, el huevo y sal hasta lograr una masa lisa.","Toma porciones, aplana en discos, rellena y cierra como empanada.","Fríe en grasa o aceite caliente hasta dorar por ambos lados.","Escurre y sirve caliente, con limón si te gusta."],ilu:{t:"empanada",c:["#E0B45B","#C98B2D","#8C4A32"]}},
{id:"py-09",pais:"Paraguay",nombre:"Kiveve",desc:"Crema agridulce de calabaza andai con harina de maíz y queso, entre plato y postre.",tiempo:45,porciones:4,dificultad:"Fácil",tipo:["comida","postre"],nivel:2,ingredientes:["1 kg de calabaza andai (zapallo) en trozos","1/2 taza de harina de maíz","150 g de queso Paraguay en trozos","2 cdas de grasa o mantequilla","2 cdas de azúcar","1 taza de leche","Sal"],pasos:["Cocina la calabaza en poca agua hasta que esté muy tierna y hazla puré con su caldo.","Vuelve al fuego con la grasa, el azúcar y una pizca de sal.","Agrega la harina de maíz en lluvia, revolviendo para que no grumee.","Cocina 10 minutos sumando leche hasta lograr una crema.","Apaga e incorpora el queso; sirve tibio como desayuno, guarnición o merienda."],ilu:{t:"bowl",c:["#E0863B","#EFC94C","#F2E3C2"]}},
{id:"py-10",pais:"Paraguay",nombre:"Tereré",desc:"La bebida nacional: yerba mate con agua helada y hierbas refrescantes, compartida en ronda.",tiempo:10,porciones:2,dificultad:"Fácil",tipo:["bebida"],nivel:1,ingredientes:["Yerba mate (de corte grueso, ideal para tereré)","1 litro de agua bien helada con hielo","Hierbas refrescantes (menta'i, cedrón, cola de caballo) machacadas","Guampa y bombilla","Rodajas de limón (opcional)"],pasos:["Machaca las hierbas en un mortero y agrégalas a la jarra de agua helada.","Llena dos tercios de la guampa con yerba.","Inclina la guampa, inserta la bombilla y moja la yerba con un primer chorro.","Ceba sirviendo agua helada y pasa la guampa: el orden de la ronda es sagrado.","Repón agua y hielo, y conversa: el tereré no se apura."],ilu:{t:"vaso",c:["#7A8C3B","#9DBE6E","#EFC94C"]}},
{id:"pe-01",pais:"Perú",nombre:"Ceviche peruano",desc:"Pescado fresco marinado en leche de tigre con ají limo, cebolla y cilantro, servido con camote y choclo.",tiempo:30,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["800 g de pescado blanco muy fresco en cubos","Jugo de 10 limones","1 cebolla roja en pluma fina","1 ají limo picado fino","1 diente de ajo molido","Cilantro picado","1 trozo de jengibre (opcional)","2 camotes cocidos","2 choclos cocidos","Sal y pimienta"],pasos:["Enjuaga la cebolla en agua fría para suavizarla.","Sazona el pescado con sal, pimienta y ajo.","Agrega el jugo de limón y el ají limo, y mezcla suavemente: la marinación toma minutos, no horas.","Incorpora la cebolla y el cilantro.","Sirve de inmediato con camote, choclo y la leche de tigre que quedó en el bowl."],ilu:{t:"plato",c:["#F2EDE3","#D98A8A","#E0863B"]}},
{id:"pe-02",pais:"Perú",nombre:"Lomo saltado",desc:"Tiras de lomo salteadas al wok con cebolla, tomate y sillao, servidas con papas fritas y arroz.",tiempo:35,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["600 g de lomo de res en tiras","2 cebollas rojas en gajos gruesos","3 tomates en gajos","1 ají amarillo en tiras","3 cdas de sillao (salsa de soya)","2 cdas de vinagre tinto","2 dientes de ajo","Cilantro","400 g de papas fritas","Arroz blanco cocido"],pasos:["Sella la carne en tandas en sartén o wok muy caliente y reserva.","Saltea ajo, cebolla y ají amarillo 1 minuto a fuego máximo.","Vuelve la carne, agrega el tomate, el sillao y el vinagre; flambea si te animas.","Saltea 2 minutos más: el tomate debe quedar entero y jugoso.","Mezcla con las papas fritas, corona con cilantro y sirve con arroz."],ilu:{t:"plato",c:["#8C4A32","#C0392B","#E8C36A"]}},
{id:"pe-03",pais:"Perú",nombre:"Ají de gallina",desc:"Pollo deshilachado en crema de ají amarillo, pan y pecanas, sobre papas con arroz.",tiempo:60,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["2 pechugas de pollo","4 ajíes amarillos sin venas licuados","4 rebanadas de pan de molde remojadas en leche","1 cebolla picada","3 dientes de ajo","1/2 taza de pecanas o nueces (opcional)","1/4 taza de queso parmesano","4 papas cocidas","Huevo duro y aceitunas","Arroz blanco"],pasos:["Cuece el pollo, deshiláchalo y reserva el caldo.","Sofríe cebolla y ajo, agrega el ají amarillo licuado y cocina 5 minutos.","Suma el pan licuado con la leche y cocina removiendo hasta espesar.","Incorpora el pollo, las pecanas molidas, el parmesano y caldo hasta lograr cremosidad.","Sirve sobre rodajas de papa, con arroz, medio huevo duro y aceituna."],ilu:{t:"plato",c:["#E3B23C","#F2E3C2","#3A2E2A"]}},
{id:"pe-04",pais:"Perú",nombre:"Causa limeña",desc:"Capas de puré de papa amarilla con ají y limón, rellenas de pollo o atún con mayonesa.",tiempo:50,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 kg de papa amarilla cocida","3 cdas de pasta de ají amarillo","Jugo de 3 limones","4 cdas de aceite","1 pechuga de pollo cocida y deshilachada (o 2 latas de atún)","1/2 taza de mayonesa","1 palta en láminas","Huevo duro y aceitunas para decorar","Sal y pimienta"],pasos:["Prensa las papas aún tibias y deja enfriar.","Amasa el puré con ají amarillo, limón, aceite, sal y pimienta hasta que quede sedoso.","Mezcla el pollo o atún con la mayonesa.","En un molde alterna capas: puré, relleno, palta y de nuevo puré.","Refrigera 30 minutos, desmolda y decora con huevo y aceitunas."],ilu:{t:"pastel",c:["#EFD27A","#F2E3C2","#9DBE6E"]}},
{id:"pe-05",pais:"Perú",nombre:"Anticuchos",desc:"Brochetas de corazón de res marinadas en ají panca y asadas a la parrilla, estrella callejera limeña.",tiempo:60,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 kg de corazón de res limpio en cubos","4 cdas de pasta de ají panca","1/4 taza de vinagre tinto","4 dientes de ajo molidos","1 cdita de comino y orégano","Aceite y sal","Palitos de brocheta","Papas doradas y choclo para acompañar","Salsa de ají"],pasos:["Marina el corazón con ají panca, vinagre, ajo, comino, orégano y sal por al menos 2 horas.","Ensarta 3–4 trozos por palito.","Asa a fuego fuerte en parrilla o plancha, pintando con la marinada.","Cocina 2–3 minutos por lado: por fuera dorado, por dentro jugoso.","Sirve con papa dorada, choclo y ají al gusto."],ilu:{t:"brocheta",c:["#8C3A2A","#C0392B","#E8C36A"]}},
{id:"pe-06",pais:"Perú",nombre:"Papa a la huancaína",desc:"Papas bañadas en salsa cremosa de ají amarillo y queso fresco, entrada infaltable.",tiempo:30,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["6 papas cocidas en rodajas","4 ajíes amarillos sin venas","200 g de queso fresco","1/2 taza de leche evaporada","4 galletas de soda","2 cdas de aceite","Hojas de lechuga","Huevo duro y aceitunas negras","Sal"],pasos:["Saltea los ajíes con un poco de aceite para suavizar su picor.","Licúa los ajíes con queso, leche, galletas y sal hasta lograr una crema espesa.","Acomoda rodajas de papa sobre hojas de lechuga.","Baña con la salsa huancaína.","Decora con huevo duro y aceitunas; sirve fría o a temperatura ambiente."],ilu:{t:"plato",c:["#EFD27A","#F2E3C2","#3A2E2A"]}},
{id:"pe-07",pais:"Perú",nombre:"Rocoto relleno",desc:"Rocotos arequipeños rellenos de carne y gratinados con queso, acompañados de pastel de papa.",tiempo:80,porciones:4,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["4 rocotos grandes","500 g de carne molida","1 cebolla picada","2 cdas de pasta de ají panca","1/4 taza de maní tostado picado","2 huevos duros picados","Pasas (opcional)","150 g de queso fresco o paria en láminas","Azúcar y vinagre para hervir los rocotos","Leche y huevo para el gratín"],pasos:["Desvena los rocotos y hiérvelos 3 veces en agua con azúcar y vinagre para domar el picante.","Sofríe cebolla con ají panca, agrega la carne y cocina; mezcla con maní, pasas y huevo duro.","Rellena los rocotos y cúbrelos con láminas de queso.","Colócalos en una fuente, baña con leche batida con huevo.","Hornea a 180 °C por 20 minutos hasta gratinar; sirve con pastel de papa."],ilu:{t:"plato",c:["#C0392B","#F2E3C2","#8C4A32"]}},
{id:"pe-08",pais:"Perú",nombre:"Arroz chaufa",desc:"Arroz frito al estilo chifa con pollo, tortilla de huevo, cebolla china y sillao.",tiempo:30,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["4 tazas de arroz cocido y frío","2 pechugas de pollo en cubos","3 huevos","1 atado de cebolla china picada","1 trozo de kion (jengibre) rallado","4 cdas de sillao","1 cdita de aceite de ajonjolí","1 pimiento rojo picado (opcional)","Aceite y sal"],pasos:["Haz una tortilla con los huevos, córtala en cuadritos y reserva.","Saltea el pollo a fuego fuerte hasta dorar.","Agrega kion, pimiento y la parte blanca de la cebolla china.","Suma el arroz frío y el sillao, salteando para que cada grano se impregne.","Termina con la tortilla, el aceite de ajonjolí y la cebolla china verde."],ilu:{t:"plato",c:["#C9A36A","#EFC94C","#5C8A4E"]}},
{id:"pe-09",pais:"Perú",nombre:"Suspiro a la limeña",desc:"Manjar blanco sedoso coronado con merengue al oporto: dulce, suave y limeñísimo.",tiempo:50,porciones:6,dificultad:"Media",tipo:["postre"],nivel:3,ingredientes:["1 lata de leche evaporada","1 lata de leche condensada","5 yemas","1 cdita de esencia de vainilla","Para el merengue: 3 claras","1 taza de azúcar","1/2 taza de oporto","Canela molida para espolvorear"],pasos:["Cocina las dos leches a fuego bajo revolviendo hasta que tome punto de manjar (ver el fondo de la olla).","Fuera del fuego agrega las yemas batidas y la vainilla; cocina 2 minutos más sin hervir.","Reparte el manjar en copas y deja entibiar.","Haz un almíbar con azúcar y oporto a punto de hilo, y viértelo en hilo sobre las claras batidas hasta lograr un merengue firme.","Corona las copas con merengue y espolvorea canela."],ilu:{t:"copa",c:["#F2E3C2","#C98B5A","#E8D9F2"]}},
{id:"pe-10",pais:"Perú",nombre:"Pisco sour",desc:"El cóctel bandera del Perú: pisco, limón, jarabe y clara de huevo coronado con amargo de angostura.",tiempo:10,porciones:2,dificultad:"Fácil",tipo:["bebida"],nivel:2,ingredientes:["6 oz (180 ml) de pisco quebranta","2 oz de jugo de limón fresco","2 oz de jarabe de goma","1 clara de huevo","Hielo abundante","Gotas de amargo de angostura"],pasos:["Pon en la coctelera el pisco, el limón, el jarabe y la clara.","Agita en seco (sin hielo) 10 segundos para emulsionar la espuma.","Agrega hielo y agita con energía 15 segundos más.","Cuela en copas frías: la espuma debe coronar el cóctel.","Decora con 3 gotas de amargo de angostura sobre la espuma."],ilu:{t:"vaso",c:["#EFE3B5","#FFF6E3","#8C4A32"]}},
{id:"uy-01",pais:"Uruguay",nombre:"Chivito al pan",desc:"El sándwich nacional uruguayo: churrasco fino con jamón, muzzarella, huevo, tomate y mayonesa.",tiempo:35,porciones:2,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["2 churrascos finos de lomo o nalga","2 panes tipo pebete o brioche grandes","2 fetas de jamón cocido","2 fetas de muzzarella","2 fetas de panceta","2 huevos","Tomate y lechuga","Mayonesa","Papas fritas para acompañar","Sal y pimienta"],pasos:["Dora la panceta y fríe los huevos; reserva.","Cocina los churrascos a la plancha 1–2 minutos por lado y cúbrelos con jamón y muzzarella para que funda.","Tuesta el pan y unta mayonesa generosamente.","Arma: lechuga, tomate, churrasco con queso, panceta y huevo frito.","Cierra, presiona apenas y sirve con papas fritas."],ilu:{t:"sandwich",c:["#E8C36A","#8C4A32","#C0392B"]}},
{id:"uy-02",pais:"Uruguay",nombre:"Asado uruguayo",desc:"Tira de asado y achuras a las brasas de leña, con ensalada criolla y tiempo por delante.",tiempo:150,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["2 kg de tira de asado","1 kg de pulpón o vacío","Chorizos y morcillas","Sal gruesa","Leña o carbón de buena calidad","Ensalada criolla: tomate, cebolla, morrón, aceite y vinagre"],pasos:["Prende el fuego con leña y espera brasas firmes: en Uruguay el asado se hace con calma.","Sala la carne con sal gruesa.","Comienza con chorizos y morcillas para el picoteo.","Cocina la tira a fuego suave 70–90 minutos, hueso abajo primero.","Da vuelta, termina de dorar y sirve con ensalada criolla y pan."],ilu:{t:"plato",c:["#8C4A32","#C0392B","#5C8A4E"]}},
{id:"uy-03",pais:"Uruguay",nombre:"Pamplona de pollo",desc:"Pechuga rellena de jamón, queso y morrón, enrollada y asada a la parrilla.",tiempo:70,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["2 pechugas grandes abiertas en mariposa","4 fetas de jamón","4 fetas de queso muzzarella o dambo","1 morrón rojo asado en tiras","2 huevos duros (opcional)","Sal, pimienta y pimentón","Hilo de cocina o malla","Aceite"],pasos:["Aplana las pechugas abiertas y salpimienta.","Cubre con jamón, queso, tiras de morrón y huevo duro.","Enrolla bien apretado y ata con hilo o coloca en malla.","Cocina a la parrilla o al horno a fuego medio 40–50 minutos, girando.","Deja reposar 5 minutos, corta en rodajas y sirve con ensalada o papas."],ilu:{t:"plato",c:["#D9A05B","#C0392B","#F2E3C2"]}},
{id:"uy-04",pais:"Uruguay",nombre:"Buseca",desc:"Guiso invernal de mondongo con porotos, panceta y verduras, herencia italiana del Río de la Plata.",tiempo:150,porciones:6,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["1 kg de mondongo limpio","250 g de porotos blancos (remojados)","150 g de panceta","2 chorizos","1 cebolla","1 zanahoria","1 morrón","2 tomates o 1 lata de tomate","1 cda de pimentón","Laurel, sal y pimienta"],pasos:["Hierve el mondongo en agua con laurel 1 hora; escurre y córtalo en tiras.","Sofríe panceta, cebolla, zanahoria y morrón en la olla.","Agrega el tomate, el pimentón, el mondongo y los porotos.","Cubre con caldo y cocina a fuego bajo 1 hora hasta que los porotos estén tiernos.","Suma el chorizo en rodajas en los últimos 20 minutos y sirve bien caliente."],ilu:{t:"bowl",c:["#C9762B","#F2E3C2","#C0392B"]}},
{id:"uy-05",pais:"Uruguay",nombre:"Puchero",desc:"Carnes y verduras hervidas lentamente: el caldo se toma de entrada y el resto es el plato principal.",tiempo:150,porciones:8,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 kg de falda o aguja","2 osobucos","1 trozo de panceta","2 chorizos","4 papas","2 batatas","4 zanahorias","2 choclos","1/2 zapallo en trozos","1 taza de garbanzos remojados y apio, puerro y repollo"],pasos:["Hierve las carnes con apio y puerro espumando el caldo durante 1 hora.","Agrega los garbanzos y cocina 30 minutos.","Suma las verduras por dureza: zanahoria primero, luego papa, batata, zapallo, choclo y repollo.","Cocina hasta que todo esté tierno y el caldo concentrado.","Sirve primero el caldo con fideos finos y luego una fuente con carnes y verduras."],ilu:{t:"bowl",c:["#E3A23B","#EFC94C","#9DBE6E"]}},
{id:"uy-06",pais:"Uruguay",nombre:"Fainá",desc:"Torta fina de harina de garbanzos al horno, compañera obligada de la pizza uruguaya.",tiempo:40,porciones:6,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["250 g de harina de garbanzos","750 ml de agua","1/2 taza de aceite de oliva","1 cdita de sal","Pimienta negra abundante"],pasos:["Mezcla la harina de garbanzos con el agua, la sal y la mitad del aceite; deja reposar 30 minutos.","Calienta el horno al máximo con una asadera con el resto del aceite adentro.","Vierte la mezcla en la asadera caliente: debe quedar de 1 cm de alto.","Hornea 20–25 minutos hasta dorar los bordes.","Corta en porciones, muele pimienta encima y sirve sola o 'a caballo' sobre la pizza."],ilu:{t:"porcion",c:["#E0B45B","#C98B2D","#3A2E2A"]}},
{id:"uy-07",pais:"Uruguay",nombre:"Tortas fritas",desc:"Discos de masa fritos en grasa con su agujero al medio, el clásico de los días de lluvia.",tiempo:60,porciones:6,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["500 g de harina","100 g de grasa vacuna (más para freír)","1 cdita de sal","Agua tibia cantidad necesaria","Azúcar para espolvorear"],pasos:["Forma una masa tierna con harina, sal, grasa derretida y agua tibia; deja descansar 30 minutos.","Toma bollos, aplánalos en discos de 1 cm.","Hazles el agujero en el centro con el dedo (clave para la cocción pareja).","Fríe en grasa bien caliente hasta dorar ambos lados.","Escurre y espolvorea con azúcar; se comen mirando llover, con mate."],ilu:{t:"pan",c:["#E0B45B","#E8C36A","#FFF6E3"]}},
{id:"uy-08",pais:"Uruguay",nombre:"Ñoquis del 29",desc:"Ñoquis de papa caseros con tuco, que se comen cada 29 con un billete bajo el plato.",tiempo:75,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 kg de papas","300 g de harina (aproximado)","1 huevo","Nuez moscada y sal","Para el tuco: cebolla, ajo, carne picada o falda, tomate triturado, laurel","Queso rallado"],pasos:["Cocina las papas con cáscara, pélalas y písalas en caliente.","Mezcla con huevo, sal, nuez moscada y la harina justa para una masa suave.","Forma rollos, corta los ñoquis y márcalos con tenedor.","Prepara el tuco: sofríe cebolla y ajo, dora la carne y cocina con el tomate 40 minutos.","Hierve los ñoquis hasta que floten, mezcla con el tuco y sirve con queso rallado (y el billete abajo del plato, por las dudas)."],ilu:{t:"plato",c:["#EFD27A","#C0392B","#F2E3C2"]}},
{id:"uy-09",pais:"Uruguay",nombre:"Postre chajá",desc:"Capas de bizcochuelo, crema, duraznos y merengue seco: el postre creado en Paysandú.",tiempo:90,porciones:8,dificultad:"Alta",tipo:["postre"],nivel:4,ingredientes:["1 bizcochuelo de vainilla","500 ml de crema doble batida con azúcar","1 lata de duraznos en almíbar","200 g de merengues secos triturados","Almíbar de los duraznos para humedecer","Dulce de leche (opcional)"],pasos:["Corta el bizcochuelo en capas y humedécelas con el almíbar de los duraznos.","Bate la crema con azúcar hasta que quede firme.","Arma capas alternando bizcochuelo, crema y duraznos en gajos.","Cubre todo el postre con crema.","Tapiza con el merengue triturado presionando suavemente y refrigera 2 horas antes de servir."],ilu:{t:"copa",c:["#FFF6E3","#E0863B","#F2E3C2"]}},
{id:"uy-10",pais:"Uruguay",nombre:"Martín Fierro",desc:"El postre más simple y querido: queso semiduro con dulce de membrillo en proporciones justas.",tiempo:5,porciones:4,dificultad:"Fácil",tipo:["postre"],nivel:1,ingredientes:["400 g de queso semiduro (colonia o dambo)","400 g de dulce de membrillo"],pasos:["Corta el queso en láminas generosas de 1 cm.","Corta el membrillo del mismo tamaño que el queso.","Apila una lámina de membrillo sobre cada lámina de queso.","Sirve a temperatura ambiente para que el queso exprese su sabor.","Disfruta el contraste: no necesita absolutamente nada más."],ilu:{t:"porcion",c:["#F2E3C2","#B5482F","#E8C36A"]}},
{id:"ve-01",pais:"Venezuela",nombre:"Arepa reina pepiada",desc:"Arepa rellena de pollo con aguacate y mayonesa, la reina indiscutida de las areperas.",tiempo:45,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["2 tazas de harina de maíz precocida","2,5 tazas de agua tibia","1 cdita de sal","1 pechuga de pollo cocida y deshilachada","1 aguacate grande maduro","1/2 taza de mayonesa","1 cda de jugo de limón","Cilantro picado (opcional)","Pimienta"],pasos:["Mezcla la harina con agua y sal, y amasa hasta lograr una masa suave sin grumos.","Forma discos de 1,5 cm y cocínalos en budare o sartén 7 minutos por lado; termina en horno si quieres que suenen huecas.","Machaca el aguacate con limón y mézclalo con el pollo, la mayonesa y pimienta.","Abre las arepas calientes con un cuchillo sin llegar al borde.","Rellena generosamente con la reina pepiada y sirve de inmediato."],ilu:{t:"arepa",c:["#F2E3C2","#9DBE6E","#E8C36A"]}},
{id:"ve-02",pais:"Venezuela",nombre:"Pabellón criollo",desc:"El plato nacional: carne mechada, caraotas negras, arroz blanco y tajadas de plátano maduro.",tiempo:120,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["500 g de falda de res","2 tazas de caraotas negras (remojadas)","2 tazas de arroz","2 plátanos maduros","1 cebolla picada","1 pimentón picado","3 dientes de ajo","2 tomates picados","1 cdita de comino","Aceite, sal y pimienta"],pasos:["Cuece la falda en agua con sal hasta que esté tierna; deshiláchala y reserva el caldo.","Cocina las caraotas en el caldo hasta ablandar y sazónalas con un sofrito.","Sofríe cebolla, ajo, pimentón y tomate; agrega la carne mechada y el comino, y cocina 15 minutos.","Prepara el arroz blanco y fríe las tajadas de maduro hasta dorar.","Sirve los cuatro componentes juntos: ese contraste es el pabellón."],ilu:{t:"plato",c:["#8C4A32","#3A2E2A","#E0A53B"]}},
{id:"ve-03",pais:"Venezuela",nombre:"Hallacas",desc:"El tamal navideño venezolano: masa de maíz con guiso de tres carnes y adornos, envuelta en hoja de plátano.",tiempo:300,porciones:12,dificultad:"Alta",tipo:["comida"],nivel:5,ingredientes:["1 kg de harina de maíz precocida","Caldo de gallina y manteca con onoto para la masa","500 g de res, 500 g de cerdo y 1/2 gallina en cubos pequeños","1 taza de vino tinto o papelón","Cebolla, ajo porro, cebollín, ajo y pimentón para el guiso","Alcaparras, aceitunas, pasas y tiras de pimentón para adornar","Hojas de plátano soasadas","Pabilo (cuerda) para amarrar","Sal, pimienta y comino"],pasos:["Prepara el guiso: cocina las carnes con todos los aliños y el vino hasta que espese; deja enfriar de un día para otro.","Amasa la harina con caldo y manteca coloreada con onoto hasta lograr una masa suave.","Extiende una bola de masa sobre la hoja engrasada, en capa fina.","Coloca guiso y adornos, dobla la hoja, forma el paquete y amárralo con pabilo.","Hierve las hallacas en agua con sal por 1 hora.","Escurre y sirve calientes; en diciembre, repetir es obligatorio."],ilu:{t:"envuelto",c:["#5C7A3E","#E3B23C","#C9A36A"]}},
{id:"ve-04",pais:"Venezuela",nombre:"Cachapas con queso",desc:"Panqueca dulce de maíz tierno doblada sobre queso de mano fundente.",tiempo:35,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["4 tazas de granos de maíz tierno (jojoto)","3 cdas de azúcar","1/2 cdita de sal","1/4 taza de leche (si hace falta)","2 cdas de harina de maíz (opcional, para dar cuerpo)","400 g de queso de mano o mozzarella fresca","Mantequilla"],pasos:["Licúa el maíz con azúcar y sal hasta obtener una mezcla espesa con textura.","Si queda muy líquida, agrega harina de maíz; si muy espesa, un poco de leche.","Vierte cucharones sobre budare o sartén enmantequillado a fuego medio.","Cocina hasta que burbujee, voltea y dora el otro lado.","Pon el queso sobre la cachapa caliente, dobla por la mitad y sirve con mantequilla."],ilu:{t:"arepa",c:["#EFD27A","#FFF6E3","#E0A53B"]}},
{id:"ve-05",pais:"Venezuela",nombre:"Tequeños",desc:"Dedos de queso envueltos en masa crujiente y fritos: el pasapalo infaltable de toda fiesta venezolana.",tiempo:60,porciones:8,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["500 g de harina de trigo","100 g de mantequilla","1 huevo","1 cdita de sal y 1 de azúcar","Agua tibia cantidad necesaria","500 g de queso blanco duro (llanero) en bastones de 1x6 cm","Aceite abundante para freír"],pasos:["Forma una masa lisa con harina, mantequilla, huevo, sal, azúcar y agua; deja reposar 30 minutos.","Estira la masa fina y corta tiras de 2 cm de ancho.","Envuelve cada bastón de queso en espiral, sellando bien los extremos para que no escape el queso.","Fríe en aceite caliente hasta que doren parejo.","Escurre y sirve calientes, con salsa rosada o guasacaca si quieres."],ilu:{t:"brocheta",c:["#E0B45B","#E8C36A","#FFF6E3"]}},
{id:"ve-06",pais:"Venezuela",nombre:"Asado negro",desc:"Muchacho redondo cocido lentamente en caramelo de papelón hasta lograr una salsa oscura y brillante.",tiempo:150,porciones:6,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["1,5 kg de muchacho redondo (corte entero de res)","150 g de papelón rallado o azúcar","1/2 taza de aceite","2 cebollas picadas","1 pimentón picado","6 dientes de ajo","2 tomates picados","1 taza de vino tinto","Laurel, sal y pimienta","Arroz blanco y tajadas para acompañar"],pasos:["Calienta el aceite con el papelón hasta que se forme un caramelo oscuro.","Sella la pieza de carne en ese caramelo por todos lados: debe quedar casi negra.","Agrega los vegetales picados y sofríe alrededor de la carne.","Vierte el vino y agua caliente hasta cubrir a la mitad; cocina tapado a fuego bajo 2 horas, girando.","Corta la carne en rodajas y redúcela en su salsa licuada hasta que brille.","Sirve con arroz blanco y tajadas de plátano."],ilu:{t:"plato",c:["#3A2E2A","#5A3A2A","#E0A53B"]}},
{id:"ve-07",pais:"Venezuela",nombre:"Empanadas venezolanas",desc:"Empanadas fritas de masa de maíz, doraditas y rellenas de carne mechada, queso o cazón.",tiempo:60,porciones:5,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["2 tazas de harina de maíz precocida","2,5 tazas de agua","1 cdita de sal y 1 de azúcar","1 cdita de onoto en aceite (para el color)","Relleno a elección: carne mechada, queso blanco rallado o cazón guisado","Aceite abundante para freír"],pasos:["Amasa la harina con agua, sal, azúcar y el aceite con onoto hasta lograr una masa suave y maleable.","Extiende una bola de masa sobre plástico engrasado, en disco delgado.","Coloca el relleno en el centro, dobla con ayuda del plástico y recorta el borde con un bol.","Fríe en aceite bien caliente hasta que infle y dore.","Escurre y sirve con guasacaca o ají dulce."],ilu:{t:"empanada",c:["#EFC94C","#E0A53B","#8C4A32"]}},
{id:"ve-08",pais:"Venezuela",nombre:"Patacón zuliano",desc:"Sándwich maracucho donde el pan son dos plátanos verdes fritos y aplanados, relleno de carne y queso.",tiempo:40,porciones:2,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["2 plátanos verdes grandes","300 g de carne mechada o de pollo","100 g de queso de año o gouda rallado","Lechuga y tomate","Salsa rosada y salsa de ajo","Aceite abundante para freír","Sal"],pasos:["Pela los plátanos, córtalos a lo largo por la mitad y fríelos 4 minutos sin dorar del todo.","Aplánalos bien (cada mitad será una 'tapa' del sándwich).","Fríelos de nuevo hasta que queden dorados y crocantes; sala al salir.","Arma el patacón: tapa de plátano, carne caliente, queso, lechuga, tomate y salsas.","Cierra con la otra tapa y sirve con servilletas: es un asunto serio."],ilu:{t:"sandwich",c:["#9DA84E","#8C4A32","#EFC94C"]}},
{id:"ve-09",pais:"Venezuela",nombre:"Quesillo",desc:"El flan venezolano: huevos enteros y leche condensada sobre caramelo, con su textura de 'huequitos'.",tiempo:75,porciones:8,dificultad:"Media",tipo:["postre"],nivel:3,ingredientes:["1 lata de leche condensada","La misma medida de leche entera","5 huevos enteros","1 cdita de vainilla","1 cda de ron (opcional)","1 taza de azúcar para el caramelo"],pasos:["Derrite el azúcar en la quesillera o molde hasta lograr un caramelo dorado y cubre fondo y paredes.","Licúa la leche condensada, la leche, los huevos, la vainilla y el ron.","Vierte la mezcla en el molde acaramelado y tapa (o cubre con papel aluminio).","Cocina a baño de María en horno a 180 °C por 50–60 minutos, hasta que un cuchillo salga limpio.","Enfría por completo en la nevera antes de desmoldar.","Desmolda con confianza y deja que el caramelo bañe el quesillo."],ilu:{t:"porcion",c:["#EFD27A","#C98038","#8C5A2A"]}},
{id:"ve-10",pais:"Venezuela",nombre:"Chicha venezolana",desc:"Bebida cremosa y helada de arroz con leche, canela y vainilla, coronada con leche condensada.",tiempo:40,porciones:4,dificultad:"Fácil",tipo:["bebida"],nivel:2,ingredientes:["1 taza de arroz","4 tazas de agua","3 tazas de leche","1 rama de canela","1 cdita de vainilla","1/2 taza de azúcar (al gusto)","Leche condensada y canela molida para servir","Hielo"],pasos:["Cocina el arroz en el agua con la rama de canela hasta que esté muy blando.","Deja entibiar y licúa con la leche, el azúcar y la vainilla hasta que quede totalmente cremosa.","Ajusta el espesor con más leche si hace falta: debe poder beberse con pitillo grueso.","Refrigera hasta que esté bien fría.","Sirve en vasos con hielo, un chorro de leche condensada y canela espolvoreada."],ilu:{t:"vaso",c:["#F2EDE3","#FFF6E3","#C98B5A"]}},
{id:"mx-01",pais:"México",nombre:"Tacos al pastor",desc:"Cerdo adobado con achiote y chiles, asado y servido en tortillas con piña, cebolla y cilantro.",tiempo:90,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["800 g de carne de cerdo en filetes delgados","3 chiles guajillo y 2 anchos (hidratados)","2 cdas de pasta de achiote","1/4 taza de vinagre","Jugo de 1 naranja","2 dientes de ajo","1 cdita de orégano y comino","12 tortillas de maíz","1/2 piña en láminas","Cebolla y cilantro picados, limones"],pasos:["Licúa los chiles con achiote, vinagre, jugo de naranja, ajo y especias para el adobo.","Marina la carne en el adobo al menos 2 horas (mejor toda la noche).","Asa la carne en plancha o sartén bien caliente junto con láminas de piña.","Pica la carne y la piña en trocitos.","Calienta las tortillas y arma los tacos con carne, piña, cebolla, cilantro y limón."],ilu:{t:"plato",c:["#B5482F","#EFC94C","#5C8A4E"]}},
{id:"mx-02",pais:"México",nombre:"Guacamole con totopos",desc:"Aguacate machacado con tomate, cebolla, chile y limón, servido con totopos crujientes.",tiempo:15,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:1,ingredientes:["3 aguacates maduros","1 tomate picado en cubitos","1/4 de cebolla blanca picada fina","1 chile serrano picado (sin semillas si lo quieres suave)","Jugo de 1 limón","Cilantro picado","Sal","Totopos de maíz para acompañar"],pasos:["Machaca los aguacates con tenedor dejando algo de textura.","Agrega el jugo de limón de inmediato para que no se oxide.","Incorpora tomate, cebolla, chile y cilantro.","Sazona con sal y mezcla apenas.","Sirve al momento con totopos; el guacamole no espera a nadie."],ilu:{t:"bowl",c:["#9DBE6E","#C0392B","#F2E3C2"]}},
{id:"mx-03",pais:"México",nombre:"Pozole rojo",desc:"Caldo festivo de maíz cacahuazintle y cerdo teñido con chiles, con su mesa de guarniciones.",tiempo:180,porciones:8,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["1 kg de maíz pozolero precocido","1 kg de carne de cerdo (espaldilla y codillo)","4 chiles guajillo y 2 anchos","1 cabeza de ajo","1 cebolla","Orégano mexicano","Para servir: lechuga rebanada, rábanos, cebolla picada, orégano, limón y tostadas","Sal"],pasos:["Cuece el maíz con media cebolla y ajos hasta que reviente como flor (1 hora si es precocido).","Agrega la carne y cocina 1 hora más hasta que esté suave; desmenúzala.","Hidrata los chiles, licúalos con ajo y un poco de caldo, y cuela.","Vierte la salsa de chiles a la olla y hierve 20 minutos; ajusta sal y orégano.","Sirve bien caliente y deja que cada quien agregue lechuga, rábano, cebolla, orégano y limón."],ilu:{t:"bowl",c:["#B5482F","#F2E3C2","#9DBE6E"]}},
{id:"mx-04",pais:"México",nombre:"Chiles en nogada",desc:"Chile poblano relleno de picadillo con frutas, bañado en nogada y granada: los colores de la bandera.",tiempo:150,porciones:6,dificultad:"Alta",tipo:["comida"],nivel:5,ingredientes:["6 chiles poblanos asados y pelados","500 g de carne molida de res y cerdo","1 manzana, 1 pera y 1 durazno picados","1/4 taza de pasas y almendras","1 plátano macho picado","Para la nogada: 1 taza de nuez de castilla, 200 g de queso crema, 1/2 taza de leche, 1 cdita de azúcar","1 granada desgranada","Perejil para decorar","Cebolla, ajo y jitomate para el picadillo"],pasos:["Prepara el picadillo: sofríe cebolla, ajo y jitomate, agrega la carne y luego las frutas; cocina hasta que seque.","Abre los chiles con cuidado, desvénalos y rellénalos con el picadillo.","Licúa la nuez con queso crema, leche y azúcar hasta lograr una crema tersa: la nogada.","Baña los chiles a temperatura ambiente con la nogada fría.","Decora con granada y perejil, y sirve: verde, blanco y rojo en el plato."],ilu:{t:"plato",c:["#5C7A3E","#F2E3C2","#B5485A"]}},
{id:"mx-05",pais:"México",nombre:"Enchiladas verdes",desc:"Tortillas rellenas de pollo bañadas en salsa verde de tomatillo, con crema y queso fresco.",tiempo:50,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["12 tortillas de maíz","2 pechugas de pollo cocidas y deshebradas","500 g de tomatillos (tomates verdes)","2 chiles serranos","1/4 de cebolla y 1 diente de ajo","Cilantro","1/2 taza de crema","100 g de queso fresco desmoronado","Aceite y sal"],pasos:["Hierve los tomatillos con los chiles 8 minutos y licúalos con cebolla, ajo, cilantro y sal.","Sofríe la salsa en una cucharada de aceite 10 minutos.","Pasa las tortillas brevemente por aceite caliente para suavizarlas.","Rellénalas con pollo, enróllalas y acomódalas en el plato.","Baña con la salsa verde caliente y termina con crema, queso y aros de cebolla."],ilu:{t:"plato",c:["#7A9E4E","#F2E3C2","#FFF6E3"]}},
{id:"mx-06",pais:"México",nombre:"Cochinita pibil",desc:"Cerdo marinado en achiote y naranja agria, cocido lentamente envuelto en hoja de plátano, estilo Yucatán.",tiempo:240,porciones:8,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["1,5 kg de pierna o espaldilla de cerdo","100 g de pasta de achiote","1 taza de jugo de naranja agria (o naranja con limón)","4 dientes de ajo","1 cdita de orégano y comino","Hojas de plátano soasadas","Para la cebolla encurtida: 2 cebollas moradas, jugo de limón, chile habanero","Tortillas de maíz","Sal"],pasos:["Disuelve el achiote en el jugo de naranja agria con ajo, especias y sal.","Marina el cerdo en esa mezcla al menos 4 horas.","Envuelve la carne con su marinada en hojas de plátano y cocina tapada a horno bajo (160 °C) por 3 horas.","Prepara la cebolla morada encurtida con limón, sal y habanero.","Deshebra la carne en su jugo y sirve en tacos con la cebolla encurtida."],ilu:{t:"envuelto",c:["#5C7A3E","#C9692B","#8C6A4A"]}},
{id:"mx-07",pais:"México",nombre:"Mole poblano con pollo",desc:"La salsa más célebre de México: chiles, especias, semillas y chocolate sobre piezas de pollo.",tiempo:180,porciones:8,dificultad:"Alta",tipo:["comida"],nivel:5,ingredientes:["8 piezas de pollo cocidas (reserva el caldo)","4 chiles mulatos, 4 anchos y 3 pasillas","2 cdas de ajonjolí y 1/4 taza de almendras","1/4 taza de pasas","1 plátano macho frito","1 tortilla y 1 pan frito","50 g de chocolate de mesa","1 cdita de canela, clavo y pimienta","1 jitomate y 1/4 de cebolla asados","Sal y azúcar al gusto"],pasos:["Desvena y tuesta los chiles, hidrátalos en agua caliente.","Fríe por separado semillas, frutos secos, pan, tortilla y plátano.","Licúa todo con jitomate, cebolla, especias y caldo, en tandas, hasta que quede terso.","Cocina la salsa a fuego bajo 40 minutos removiendo; agrega el chocolate y ajusta sal y azúcar.","Baña las piezas de pollo y sirve con arroz rojo y ajonjolí tostado por encima."],ilu:{t:"plato",c:["#5A3A2A","#8C4A32","#F2E3C2"]}},
{id:"mx-08",pais:"México",nombre:"Sopa azteca",desc:"Sopa de tortilla con caldo de jitomate, tiras fritas, aguacate, queso y chile pasilla.",tiempo:45,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["8 tortillas de maíz en tiras","6 jitomates","1/4 de cebolla y 2 dientes de ajo","1 litro de caldo de pollo","2 chiles pasilla","1 aguacate en cubos","100 g de queso panela o fresco","1/2 taza de crema","Aceite y sal","Epazote (opcional)"],pasos:["Fríe las tiras de tortilla hasta dorar y escúrrelas; fríe también aros de chile pasilla.","Licúa los jitomates con cebolla y ajo, y sofríe la salsa 10 minutos.","Agrega el caldo y el epazote, y hierve 15 minutos; sala.","Reparte las tiras de tortilla en los platos y vierte el caldo encima.","Corona con aguacate, queso, crema y los aros de pasilla."],ilu:{t:"bowl",c:["#C0532B","#E8C36A","#9DBE6E"]}},
{id:"mx-09",pais:"México",nombre:"Agua de horchata",desc:"Bebida fresca de arroz con canela y vainilla, dulce y lechosa, infaltable en las taquerías.",tiempo:30,porciones:6,dificultad:"Fácil",tipo:["bebida"],nivel:1,ingredientes:["1 taza de arroz","1 rama de canela","4 tazas de agua","1 taza de leche (o leche evaporada)","1/2 taza de azúcar (al gusto)","1 cdita de vainilla","Hielo y canela molida para servir"],pasos:["Remoja el arroz con la canela en 2 tazas de agua caliente por 2 horas (o desde la víspera).","Licúa el arroz con su agua de remojo hasta molerlo bien.","Cuela con manta o colador fino apretando bien.","Mezcla con el resto del agua, la leche, el azúcar y la vainilla.","Sirve muy fría con hielo y una pizca de canela molida."],ilu:{t:"vaso",c:["#F2EDE3","#FFF6E3","#C98B5A"]}},
{id:"mx-10",pais:"México",nombre:"Flan napolitano",desc:"Flan cremoso de queso y leche condensada con caramelo dorado, el final clásico de la comida mexicana.",tiempo:80,porciones:8,dificultad:"Media",tipo:["postre"],nivel:3,ingredientes:["1 taza de azúcar para el caramelo","1 lata de leche condensada","1 lata de leche evaporada","190 g de queso crema","4 huevos","1 cdita de vainilla"],pasos:["Derrite el azúcar a fuego medio hasta lograr un caramelo ámbar y cubre el molde.","Licúa las leches con el queso crema, los huevos y la vainilla.","Vierte sobre el caramelo y tapa el molde con papel aluminio.","Hornea a baño de María a 180 °C por 50–60 minutos, hasta que cuaje.","Enfría por completo en el refrigerador antes de desmoldar."],ilu:{t:"porcion",c:["#EFD27A","#C98038","#8C5A2A"]}},
{id:"es-01",pais:"España",nombre:"Paella valenciana",desc:"Arroz dorado al azafrán con pollo, conejo y judías, cocido en paella ancha hasta lograr el socarrat.",tiempo:90,porciones:6,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["400 g de arroz bomba","600 g de pollo troceado","400 g de conejo troceado (opcional)","200 g de judía verde plana","150 g de garrofón (judía blanca grande)","2 tomates rallados","Hebras de azafrán","1 cdita de pimentón dulce","1,2 litros de caldo o agua","Aceite de oliva, romero y sal"],pasos:["Dora el pollo y el conejo en la paella con aceite de oliva y sal.","Agrega las judías y sofríe; suma el tomate rallado y el pimentón sin que se queme.","Vierte el caldo, agrega el azafrán y hierve 20 minutos para hacer el fondo.","Reparte el arroz en forma de cruz y cocina 18 minutos sin remover jamás: 10 a fuego fuerte, 8 a fuego suave.","Sube el fuego 1 minuto al final para el socarrat, tapa con un paño y reposa 5 minutos antes de servir."],ilu:{t:"plato",c:["#E3A23B","#C0392B","#5C8A4E"]}},
{id:"es-02",pais:"España",nombre:"Tortilla de patatas",desc:"El icono español: huevo y papas confitadas en aceite de oliva, jugosa por dentro.",tiempo:40,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["6 huevos","4 papas medianas en láminas finas","1 cebolla en juliana (opcional pero recomendada)","Aceite de oliva abundante","Sal"],pasos:["Confita las papas (y la cebolla) en aceite a fuego medio-bajo hasta que estén tiernas, sin dorar demasiado.","Escurre bien y mezcla con los huevos batidos y sal; deja reposar 5 minutos.","Vierte en sartén antiadherente con un poco de aceite a fuego medio.","Cuando cuaje por abajo, da la vuelta con ayuda de un plato.","Cocina 1–2 minutos más: por dentro debe quedar jugosa. Sirve tibia."],ilu:{t:"porcion",c:["#EFD27A","#E3B23C","#F2E3C2"]}},
{id:"es-03",pais:"España",nombre:"Gazpacho andaluz",desc:"Sopa fría de tomate, pepino y pimiento con aceite de oliva: verano andaluz en vaso.",tiempo:15,porciones:4,dificultad:"Fácil",tipo:["comida","bebida"],nivel:1,ingredientes:["1 kg de tomates maduros","1 pepino pequeño","1 pimiento verde italiano","1 diente de ajo","50 g de pan del día anterior","1/4 taza de aceite de oliva virgen extra","2 cdas de vinagre de Jerez","Sal","Guarnición: tomate, pepino y pan en daditos"],pasos:["Trocea las verduras y remoja el pan en un poco de agua.","Licúa todo con el ajo, el vinagre y la sal hasta que quede muy fino.","Emulsiona agregando el aceite en hilo con la licuadora andando.","Cuela si lo quieres más sedoso y refrigera al menos 2 horas.","Sirve muy frío, en vaso o en plato con la guarnición en daditos."],ilu:{t:"vaso",c:["#C9442E","#E0863B","#9DBE6E"]}},
{id:"es-04",pais:"España",nombre:"Croquetas de jamón",desc:"Bechamel cremosa con jamón serrano, empanada y frita: la tapa que mide a todo bar.",tiempo:90,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["150 g de jamón serrano picado fino","80 g de mantequilla","100 g de harina","800 ml de leche","Nuez moscada y pimienta","2 huevos batidos","Pan rallado","Aceite de oliva para freír","Sal (poca: el jamón ya es salado)"],pasos:["Derrite la mantequilla, sofríe el jamón y agrega la harina; cocínala 2 minutos.","Vierte la leche caliente poco a poco, removiendo hasta lograr una bechamel espesa y sin grumos (15 minutos).","Sazona con nuez moscada, extiende en una fuente, cubre con film a piel y refrigera 4 horas.","Forma las croquetas, pásalas por huevo y pan rallado.","Fríe en aceite bien caliente en tandas pequeñas hasta dorar; escurre y sirve."],ilu:{t:"pan",c:["#C98B2D","#E0B45B","#F2E3C2"]}},
{id:"es-05",pais:"España",nombre:"Pulpo a la gallega",desc:"Pulpo tierno sobre papas, con pimentón, sal gruesa y aceite de oliva: pura Galicia.",tiempo:80,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 pulpo de 2 kg (mejor congelado previamente: ablanda)","4 papas gallegas","Pimentón dulce (y un toque de picante)","Aceite de oliva virgen extra","Sal gruesa","1 hoja de laurel"],pasos:["Hierve agua con laurel y 'asusta' el pulpo: mételo y sácalo 3 veces para que los tentáculos se ricen.","Cuécelo 35–40 minutos hasta que esté tierno al pincharlo; déjalo reposar 10 minutos en el agua.","Cuece las papas en rodajas gruesas en esa misma agua.","Corta el pulpo en rodajas con tijera y móntalo sobre las papas.","Espolvorea pimentón y sal gruesa, y riega generosamente con aceite de oliva."],ilu:{t:"plato",c:["#C96A85","#EFD27A","#B5482F"]}},
{id:"es-06",pais:"España",nombre:"Cocido madrileño",desc:"Garbanzos, carnes y verduras en tres vuelcos: la sopa, los garbanzos y las carnes.",tiempo:210,porciones:8,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["500 g de garbanzos remojados","500 g de morcillo de res","1/4 de gallina","100 g de tocino","2 chorizos y 1 morcilla","1 hueso de jamón","4 papas y 4 zanahorias","1/2 repollo","Fideos finos para la sopa","Sal"],pasos:["Pon a cocer las carnes, el tocino y el hueso en agua fría; espuma el caldo.","Agrega los garbanzos en red o malla y cocina a fuego suave 2 horas.","Suma papas, zanahorias y el chorizo; cocina 30 minutos (la morcilla, aparte para que no tiña).","Saltea el repollo cocido con ajo y pimentón.","Sirve en vuelcos: primero la sopa con fideos, luego garbanzos con verduras, y al final las carnes troceadas."],ilu:{t:"bowl",c:["#E0B45B","#C0392B","#9DBE6E"]}},
{id:"es-07",pais:"España",nombre:"Patatas bravas",desc:"Papas fritas en cubos con salsa brava picante y alioli: la tapa más disputada de España.",tiempo:40,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["6 papas en cubos irregulares","Aceite de oliva para freír","Para la brava: 2 cdas de aceite, 1 cdita de pimentón picante, 1 de dulce, 1 cda de harina, 1 taza de caldo","Para el alioli: 1 diente de ajo, 1 huevo, aceite de oliva suave, sal y limón"],pasos:["Cuece los cubos de papa 5 minutos, sécalos y fríelos en aceite caliente hasta dorar.","Para la brava: sofríe el pimentón con la harina, agrega caldo y remueve hasta espesar.","Para el alioli: licúa huevo, ajo y sal agregando aceite en hilo hasta emulsionar; termina con limón.","Sirve las papas bien calientes.","Nápalas con la brava y el alioli por encima, sin miedo."],ilu:{t:"plato",c:["#E8C36A","#C0392B","#FFF6E3"]}},
{id:"es-08",pais:"España",nombre:"Churros con chocolate",desc:"Masa frita y crujiente espolvoreada con azúcar, para mojar en chocolate espeso.",tiempo:45,porciones:4,dificultad:"Media",tipo:["postre"],nivel:3,ingredientes:["250 g de harina","250 ml de agua","1 pizca de sal","Aceite de girasol u oliva suave para freír","Azúcar para rebozar","Para el chocolate: 200 g de chocolate negro, 500 ml de leche, 1 cda de maicena, 2 cdas de azúcar"],pasos:["Hierve el agua con sal, viértela de golpe sobre la harina y mezcla hasta lograr una masa densa.","Pon la masa en una churrera o manga con boquilla rizada.","Fríe tiras de masa en aceite caliente hasta que estén doradas y crujientes.","Escurre y reboza en azúcar.","Para el chocolate, calienta la leche con la maicena disuelta y el azúcar, agrega el chocolate y remueve hasta espesar; sirve para mojar."],ilu:{t:"brocheta",c:["#C98B2D","#E0B45B","#5A3A2A"]}},
{id:"es-09",pais:"España",nombre:"Sangría",desc:"Vino tinto con fruta, cítricos y un toque dulce: la jarra que preside el verano español.",tiempo:15,porciones:6,dificultad:"Fácil",tipo:["bebida"],nivel:1,ingredientes:["1 botella de vino tinto joven","1 naranja y 1 limón en rodajas","1 manzana y 1 durazno en trozos","2 cdas de azúcar","1 rama de canela","100 ml de licor de naranja (opcional)","Gaseosa o soda al gusto","Hielo abundante"],pasos:["Disuelve el azúcar en un poco de vino en la jarra.","Agrega la fruta, la canela, el licor y el resto del vino.","Refrigera al menos 2 horas para que la fruta perfume.","Completa con un golpe de gaseosa justo antes de servir.","Sirve con mucho hielo y fruta en cada vaso."],ilu:{t:"vaso",c:["#8C2B3A","#C0392B","#E0863B"]}},
{id:"es-10",pais:"España",nombre:"Crema catalana",desc:"Crema de yemas perfumada con cítricos y canela, con costra de azúcar caramelizada.",tiempo:40,porciones:6,dificultad:"Media",tipo:["postre"],nivel:3,ingredientes:["1 litro de leche","8 yemas","200 g de azúcar (más extra para quemar)","40 g de maicena","Piel de 1 limón y de 1 naranja","1 rama de canela"],pasos:["Infusiona la leche con las pieles de cítricos y la canela 10 minutos; cuela.","Bate las yemas con el azúcar y la maicena.","Vierte la leche caliente sobre las yemas removiendo, y devuelve al fuego suave hasta que espese sin hervir.","Reparte en cazuelitas y refrigera 4 horas.","Antes de servir, espolvorea azúcar y quema con soplete o hierro caliente hasta formar la costra crujiente."],ilu:{t:"taza",c:["#EFD27A","#F2E3C2","#C98038"]}},
{id:"it-01",pais:"Italia",nombre:"Pasta carbonara",desc:"Espaguetis con guanciale, huevo, pecorino y pimienta: la receta romana sin crema, como debe ser.",tiempo:25,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["400 g de espaguetis","150 g de guanciale o panceta en tiras","4 yemas y 1 huevo entero","100 g de queso pecorino rallado (o parmesano)","Pimienta negra recién molida","Sal para el agua"],pasos:["Dora el guanciale en sartén a fuego medio hasta que suelte su grasa y quede crujiente.","Cuece la pasta al dente en agua con sal; reserva una taza del agua de cocción.","Bate las yemas con el huevo, el queso y mucha pimienta.","Mezcla la pasta caliente con el guanciale fuera del fuego, agrega la crema de huevo y un poco de agua de cocción.","Remueve enérgicamente hasta lograr una salsa sedosa (el calor de la pasta cuaja el huevo sin hacerlo tortilla) y sirve ya."],ilu:{t:"plato",c:["#EFD27A","#8C5A3A","#3A2E2A"]}},
{id:"it-02",pais:"Italia",nombre:"Pizza margherita",desc:"Masa de fermentación lenta con tomate, mozzarella y albahaca: los colores de Italia en el horno.",tiempo:120,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["500 g de harina de fuerza","325 ml de agua","10 g de sal","3 g de levadura seca","400 g de tomate triturado de lata","250 g de mozzarella fresca","Hojas de albahaca","Aceite de oliva"],pasos:["Mezcla harina, agua, levadura y sal; amasa 10 minutos y deja fermentar 2 horas (mejor: 24 en frío).","Divide en bolas y estira con las manos dejando el borde grueso.","Cubre con tomate triturado salado, sin llegar al borde.","Hornea sobre piedra o bandeja precalentada al máximo del horno 6–8 minutos.","Agrega la mozzarella a mitad de cocción y la albahaca al salir, con un hilo de aceite de oliva."],ilu:{t:"porcion",c:["#E0B45B","#C0392B","#FFF6E3"]}},
{id:"it-03",pais:"Italia",nombre:"Lasaña boloñesa",desc:"Capas de pasta, ragú de carne cocido despacio y bechamel, gratinadas al horno.",tiempo:150,porciones:8,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["12 láminas de lasaña","500 g de carne molida de res y 200 g de cerdo","1 cebolla, 1 zanahoria y 1 tallo de apio picados","400 g de tomate triturado","1/2 taza de vino tinto","Para la bechamel: 60 g de mantequilla, 60 g de harina, 800 ml de leche, nuez moscada","150 g de parmesano rallado","Aceite de oliva, sal y pimienta"],pasos:["Haz el ragú: sofríe el picado de verduras, dora las carnes, agrega el vino y luego el tomate; cocina a fuego mínimo 1 hora.","Prepara la bechamel cocinando mantequilla y harina, y agregando la leche caliente hasta espesar.","Arma capas: bechamel, pasta, ragú, bechamel y parmesano; repite hasta terminar.","Cubre la última capa con bechamel y abundante parmesano.","Hornea a 180 °C por 35 minutos hasta gratinar; reposa 10 minutos antes de cortar."],ilu:{t:"pastel",c:["#C0532B","#E8C36A","#EFD27A"]}},
{id:"it-04",pais:"Italia",nombre:"Risotto ai funghi",desc:"Arroz carnaroli cremoso con hongos, mantecado con parmesano y mantequilla fría.",tiempo:45,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["320 g de arroz carnaroli o arborio","300 g de hongos frescos (y 20 g de porcini secos hidratados)","1 litro de caldo de verduras caliente","1/2 taza de vino blanco","1 cebolla pequeña picada fina","60 g de mantequilla","80 g de parmesano rallado","Aceite de oliva, sal y pimienta","Perejil picado"],pasos:["Saltea los hongos a fuego fuerte y reserva.","Sofríe la cebolla, agrega el arroz y tuéstalo 2 minutos; desglasa con el vino.","Agrega el caldo caliente de a cucharones, removiendo, durante 16–18 minutos.","Incorpora los hongos a mitad de cocción.","Fuera del fuego, manteca con la mantequilla fría y el parmesano; debe quedar fluido ('all'onda'). Sirve con perejil."],ilu:{t:"plato",c:["#EFE3C2","#8C6A4A","#5C8A4E"]}},
{id:"it-05",pais:"Italia",nombre:"Ossobuco a la milanesa",desc:"Jarrete de res estofado en vino blanco con gremolata de limón, clásico lombardo.",tiempo:150,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["4 ruedas de ossobuco (jarrete con hueso)","Harina para enharinar","1 cebolla, 1 zanahoria y 1 apio picados","1 taza de vino blanco","2 tazas de caldo","1 cda de concentrado de tomate","Para la gremolata: ralladura de limón, ajo y perejil picados","Mantequilla y aceite de oliva","Sal y pimienta"],pasos:["Enharina las ruedas y dóralas en mantequilla con aceite; reserva.","Sofríe las verduras en la misma olla y desglasa con el vino.","Vuelve la carne, agrega caldo y concentrado de tomate, y cocina tapado a fuego bajo 2 horas.","La carne debe casi desprenderse del hueso; reduce la salsa si hace falta.","Espolvorea la gremolata al servir, tradicionalmente con risotto a la milanesa."],ilu:{t:"plato",c:["#8C5A3A","#E0A53B","#5C8A4E"]}},
{id:"it-06",pais:"Italia",nombre:"Focaccia",desc:"Pan plano de oliva con hoyuelos, romero y sal gruesa, esponjoso y dorado.",tiempo:150,porciones:8,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["500 g de harina","350 ml de agua tibia","7 g de levadura seca","10 g de sal","50 ml de aceite de oliva (más para la bandeja y la superficie)","Romero fresco","Sal gruesa en escamas"],pasos:["Mezcla harina, agua, levadura y sal hasta lograr una masa húmeda; agrega el aceite y amasa.","Deja fermentar 1 hora hasta doblar volumen.","Extiende en bandeja aceitada y deja levar 40 minutos más.","Hunde los dedos haciendo hoyuelos, riega con aceite, romero y sal gruesa.","Hornea a 220 °C por 20–25 minutos hasta dorar."],ilu:{t:"pastel",c:["#E0B45B","#C98B2D","#5C8A4E"]}},
{id:"it-07",pais:"Italia",nombre:"Ensalada caprese",desc:"Tomate, mozzarella fresca y albahaca con aceite de oliva: simpleza de Capri.",tiempo:10,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:1,ingredientes:["4 tomates maduros en rodajas","250 g de mozzarella fresca (de búfala si es posible)","Hojas de albahaca fresca","Aceite de oliva virgen extra","Sal en escamas y pimienta","Orégano (opcional)"],pasos:["Corta tomates y mozzarella en rodajas del mismo grosor.","Alterna rodajas de tomate y mozzarella en el plato.","Intercala hojas de albahaca.","Sazona con sal en escamas y pimienta.","Riega con buen aceite de oliva justo antes de servir; nada más, nada menos."],ilu:{t:"plato",c:["#C0392B","#FFF6E3","#5C8A4E"]}},
{id:"it-08",pais:"Italia",nombre:"Tiramisú",desc:"Capas de bizcochos al café con crema de mascarpone y cacao, el postre italiano universal.",tiempo:40,porciones:8,dificultad:"Fácil",tipo:["postre"],nivel:2,ingredientes:["500 g de queso mascarpone","4 huevos (yemas y claras separadas)","100 g de azúcar","300 g de bizcochos savoiardi (vainillas)","2 tazas de café espresso frío","2 cdas de licor de café o marsala (opcional)","Cacao amargo para espolvorear"],pasos:["Bate las yemas con el azúcar hasta blanquear e incorpora el mascarpone.","Bate las claras a nieve y únelas con movimientos envolventes.","Moja los bizcochos brevemente en el café (con el licor) y forma una capa.","Alterna capas de crema y bizcochos, terminando con crema.","Refrigera al menos 4 horas y espolvorea cacao amargo antes de servir."],ilu:{t:"porcion",c:["#F2E8D5","#8C5A3A","#5A3A2A"]}},
{id:"it-09",pais:"Italia",nombre:"Panna cotta",desc:"Crema de vainilla apenas cuajada que tiembla en el plato, con salsa de frutos rojos.",tiempo:30,porciones:6,dificultad:"Fácil",tipo:["postre"],nivel:2,ingredientes:["500 ml de crema de leche","100 ml de leche","80 g de azúcar","1 vaina de vainilla (o 1 cdita de esencia)","4 g de gelatina sin sabor (2 hojas)","200 g de frutos rojos","2 cdas de azúcar extra para la salsa"],pasos:["Hidrata la gelatina en agua fría.","Calienta la crema con la leche, el azúcar y la vainilla sin que hierva.","Disuelve la gelatina escurrida en la mezcla caliente.","Vierte en moldes y refrigera al menos 4 horas: debe temblar, no estar dura.","Cocina los frutos rojos con azúcar 5 minutos y sirve la panna cotta desmoldada con esa salsa."],ilu:{t:"copa",c:["#FFF6E3","#F2E3C2","#B5485A"]}},
{id:"it-10",pais:"Italia",nombre:"Aperol spritz",desc:"El aperitivo veneciano naranja brillante: prosecco, Aperol y soda con hielo.",tiempo:5,porciones:2,dificultad:"Fácil",tipo:["bebida"],nivel:1,ingredientes:["180 ml de prosecco","120 ml de Aperol","Un golpe de soda","Hielo abundante","2 rodajas de naranja"],pasos:["Llena dos copas grandes de vino con hielo.","Vierte el prosecco primero (así el Aperol no se hunde).","Agrega el Aperol y completa con un golpe de soda.","Remueve apenas, una sola vez.","Decora con la rodaja de naranja y brinda: salute."],ilu:{t:"vaso",c:["#E0863B","#F2C28A","#DD8436"]}},
{id:"fr-01",pais:"Francia",nombre:"Ratatouille",desc:"Verduras de Provenza estofadas en tomate con hierbas: humilde, colorida y deliciosa.",tiempo:60,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["1 berenjena en cubos","2 zucchinis (calabacines) en cubos","1 pimiento rojo y 1 amarillo","4 tomates maduros picados","1 cebolla picada","3 dientes de ajo","Hierbas de Provenza (tomillo, romero, laurel)","Aceite de oliva","Sal y pimienta"],pasos:["Saltea cada verdura por separado en aceite de oliva para que conserve su textura.","En la misma olla sofríe cebolla y ajo, y agrega el tomate con las hierbas.","Incorpora todas las verduras a la salsa.","Cocina a fuego bajo 25 minutos, removiendo con suavidad.","Rectifica sal y sirve caliente o tibia; al día siguiente está aún mejor."],ilu:{t:"bowl",c:["#C0532B","#9DBE6E","#EFC94C"]}},
{id:"fr-02",pais:"Francia",nombre:"Quiche lorraine",desc:"Tarta salada de masa quebrada con crema, huevos y panceta ahumada, orgullo de Lorena.",tiempo:75,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["Para la masa: 250 g de harina, 125 g de mantequilla fría, 1 huevo, pizca de sal","200 g de panceta ahumada en tiras (lardons)","3 huevos","200 ml de crema de leche","100 ml de leche","Nuez moscada y pimienta","100 g de queso gruyère rallado (opcional)"],pasos:["Haz la masa mezclando harina, mantequilla, huevo y sal; refrigera 30 minutos y forra un molde.","Hornea la masa en blanco 15 minutos a 180 °C (con peso encima).","Dora la panceta en sartén sin aceite.","Bate huevos, crema, leche, nuez moscada y pimienta; agrega la panceta y el queso.","Vierte sobre la masa y hornea 30 minutos hasta que cuaje y dore."],ilu:{t:"porcion",c:["#EFD27A","#C98B5A","#E8C36A"]}},
{id:"fr-03",pais:"Francia",nombre:"Boeuf bourguignon",desc:"Res estofada en vino tinto de Borgoña con champiñones, cebollitas y panceta.",tiempo:210,porciones:6,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["1,2 kg de carne de res para estofar en cubos grandes","1 botella de vino tinto","150 g de panceta en tiras","250 g de champiñones","12 cebollitas perla","2 zanahorias en rodajas","2 dientes de ajo","1 cda de harina","Bouquet garni (tomillo, laurel, perejil)","Mantequilla, sal y pimienta"],pasos:["Marina la carne en el vino con el bouquet garni desde la víspera (opcional pero recomendado).","Dora la panceta y luego la carne escurrida, en tandas, en mantequilla.","Espolvorea la harina sobre la carne, agrega el vino de la marinada, ajo y zanahoria.","Cocina tapado a fuego mínimo (o al horno a 150 °C) durante 3 horas.","Saltea champiñones y cebollitas, agrégalos al final y sirve con puré o papas al vapor."],ilu:{t:"bowl",c:["#5A2E3A","#8C4A32","#C9A36A"]}},
{id:"fr-04",pais:"Francia",nombre:"Sopa de cebolla gratinada",desc:"Cebollas caramelizadas en caldo, coronadas con pan y gruyère fundido al horno.",tiempo:80,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["6 cebollas grandes en juliana fina","50 g de mantequilla","1 cda de harina","1/2 taza de vino blanco","1,2 litros de caldo de res","4 rebanadas de pan baguette tostado","150 g de queso gruyère rallado","Tomillo, sal y pimienta"],pasos:["Cocina las cebollas en mantequilla a fuego bajo 40 minutos hasta que caramelicen (paciencia: es el secreto).","Espolvorea la harina, cocina 2 minutos y desglasa con el vino.","Agrega el caldo y el tomillo, y hierve a fuego suave 20 minutos.","Sirve en cuencos aptos para horno, con el pan tostado encima.","Cubre con gruyère y gratina hasta que burbujee y dore."],ilu:{t:"bowl",c:["#C9913D","#E8C36A","#EFD27A"]}},
{id:"fr-05",pais:"Francia",nombre:"Croque monsieur",desc:"Sándwich caliente de jamón y queso con bechamel gratinada: el bistró en dos panes.",tiempo:30,porciones:2,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["4 rebanadas de pan de molde grueso","2 fetas generosas de jamón cocido","100 g de queso gruyère rallado","Para la bechamel: 20 g de mantequilla, 20 g de harina, 200 ml de leche, nuez moscada","Mantequilla para untar"],pasos:["Prepara una bechamel espesa con mantequilla, harina y leche; sazona con nuez moscada.","Unta el pan con bechamel, arma con jamón y parte del queso, y cierra.","Cubre la parte superior con más bechamel y el resto del gruyère.","Hornea a 200 °C unos 10 minutos y gratina al final.","Sirve caliente; con un huevo frito encima se convierte en croque madame."],ilu:{t:"sandwich",c:["#E8C36A","#D98A8A","#EFD27A"]}},
{id:"fr-06",pais:"Francia",nombre:"Coq au vin",desc:"Pollo guisado largamente en vino tinto con panceta y champiñones, clásico de bistró.",tiempo:120,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["1 pollo grande en presas","750 ml de vino tinto","150 g de panceta en tiras","250 g de champiñones","12 cebollitas perla","2 zanahorias","2 dientes de ajo","1 cda de harina","Bouquet garni","Mantequilla, sal y pimienta"],pasos:["Dora la panceta y luego las presas de pollo en su grasa con mantequilla.","Agrega las verduras, espolvorea harina y remueve.","Vierte el vino, suma el bouquet garni y cocina tapado a fuego bajo 1 hora.","Saltea champiñones y cebollitas e incorpóralos los últimos 15 minutos.","Reduce la salsa hasta que nape la cuchara y sirve con papas o baguette."],ilu:{t:"plato",c:["#6E3A4A","#8C4A32","#9DBE6E"]}},
{id:"fr-07",pais:"Francia",nombre:"Ensalada niçoise",desc:"Atún, huevo, judías verdes, aceitunas y anchoas: el sur de Francia en un plato fresco.",tiempo:25,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:1,ingredientes:["2 latas de atún en aceite de oliva","4 huevos duros en cuartos","200 g de judías verdes cocidas","4 tomates en gajos","1 pimiento verde en tiras","Aceitunas negras de Niza","8 filetes de anchoa","Vinagreta: aceite de oliva, vinagre, mostaza Dijon, sal"],pasos:["Cuece las judías verdes 5 minutos y enfríalas en agua con hielo para fijar el color.","Prepara la vinagreta batiendo mostaza, vinagre, sal y aceite en hilo.","Dispón tomates, judías, pimiento y huevo en una fuente.","Reparte el atún en lascas, las aceitunas y las anchoas.","Aliña con la vinagreta justo antes de servir."],ilu:{t:"plato",c:["#9DBE6E","#C0392B","#3A2E2A"]}},
{id:"fr-08",pais:"Francia",nombre:"Crème brûlée",desc:"Crema de vainilla sedosa bajo una lámina de caramelo que cruje al primer golpe de cuchara.",tiempo:70,porciones:6,dificultad:"Media",tipo:["postre"],nivel:3,ingredientes:["500 ml de crema de leche","1 vaina de vainilla","6 yemas","100 g de azúcar (más extra para quemar)"],pasos:["Infusiona la crema con la vainilla abierta y raspada, sin que hierva.","Bate las yemas con el azúcar y vierte la crema caliente en hilo, removiendo.","Reparte en cazuelitas bajas y hornea a baño de María a 150 °C por 40 minutos: debe temblar al centro.","Refrigera al menos 4 horas.","Espolvorea azúcar y carameliza con soplete hasta formar la costra; sirve de inmediato."],ilu:{t:"taza",c:["#EFD27A","#FFF6E3","#C98038"]}},
{id:"fr-09",pais:"Francia",nombre:"Crêpes dulces",desc:"Panqueques finísimos para rellenar con azúcar y limón, mermelada o chocolate.",tiempo:40,porciones:4,dificultad:"Fácil",tipo:["postre"],nivel:2,ingredientes:["250 g de harina","3 huevos","500 ml de leche","30 g de mantequilla derretida","1 cda de azúcar","1 pizca de sal","1 cdita de vainilla o ron","Rellenos: azúcar y limón, mermelada, chocolate o crema de avellanas"],pasos:["Licúa todos los ingredientes hasta lograr una mezcla fluida sin grumos; reposa 30 minutos.","Calienta una sartén antiadherente apenas enmantequillada.","Vierte un cucharón pequeño y gira la sartén para cubrirla en capa fina.","Cocina 1 minuto, voltea y dora 30 segundos más.","Rellena al gusto, dobla en triángulo o enrolla, y sirve calientes."],ilu:{t:"arepa",c:["#EFD27A","#C98038","#F2E3C2"]}},
{id:"fr-10",pais:"Francia",nombre:"Vin chaud",desc:"Vino caliente especiado con naranja, canela y clavo: el abrazo de los mercados de invierno.",tiempo:20,porciones:4,dificultad:"Fácil",tipo:["bebida"],nivel:1,ingredientes:["1 botella de vino tinto","1 naranja en rodajas","2 ramas de canela","4 clavos de olor","1 anís estrellado","3 cdas de azúcar o miel","1 trozo de jengibre (opcional)"],pasos:["Pon el vino con todas las especias, la naranja y el azúcar en una olla.","Calienta a fuego suave sin que llegue a hervir (el hervor evapora el alcohol y amarga).","Mantén a fuego mínimo 15 minutos para que infusione.","Cuela o sirve directamente con un cucharón.","Bebe caliente en taza, con una rodaja de naranja dentro."],ilu:{t:"taza",c:["#6E3A4A","#F2E3C2","#E0863B"]}},
{id:"cn-01",pais:"China",nombre:"Jiaozi (dumplings)",desc:"Empanadillas chinas de cerdo y col, hervidas o doradas en sartén, con salsa de soya y vinagre.",tiempo:90,porciones:6,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["40 láminas de masa para dumplings (o masa casera de harina y agua)","400 g de carne molida de cerdo","2 tazas de col china picada fina","2 cebollines picados","1 cda de jengibre rallado","2 cdas de salsa de soya","1 cda de aceite de sésamo","Para la salsa: soya, vinagre negro y ají en aceite"],pasos:["Mezcla el cerdo con la col (exprimida), cebollín, jengibre, soya y aceite de sésamo.","Pon una cucharadita de relleno en cada lámina, moja el borde y cierra con pliegues.","Para hervirlos: cocínalos en agua hirviendo hasta que floten más 2 minutos.","Para dorarlos: fríe la base en sartén, agrega un chorro de agua y tapa hasta evaporar.","Sirve calientes con la salsa de soya, vinagre y ají para mojar."],ilu:{t:"empanada",c:["#F2E8D5","#E0C9A0","#C0392B"]}},
{id:"cn-02",pais:"China",nombre:"Chow mein de pollo",desc:"Fideos salteados al wok con pollo y verduras crujientes, rápidos y llenos de sabor.",tiempo:30,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["400 g de fideos chinos de huevo","2 pechugas de pollo en tiras","1 pimiento en tiras","2 zanahorias en bastones","2 tazas de repollo en tiras","3 cebollines","3 cdas de salsa de soya","1 cda de salsa de ostras","1 cdita de jengibre y 2 dientes de ajo","Aceite vegetal"],pasos:["Cuece los fideos 2 minutos menos de lo indicado, escurre y mézclalos con unas gotas de aceite.","Saltea el pollo a fuego máximo en el wok hasta dorar; reserva.","Saltea ajo, jengibre y las verduras 2 minutos: deben quedar crujientes.","Vuelve el pollo, agrega los fideos y las salsas.","Saltea todo 2 minutos más moviendo constantemente y sirve con cebollín."],ilu:{t:"plato",c:["#E0B45B","#C0532B","#5C8A4E"]}},
{id:"cn-03",pais:"China",nombre:"Cerdo agridulce",desc:"Trozos de cerdo crocantes en salsa brillante de piña, vinagre y pimiento, estilo cantonés.",tiempo:45,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["500 g de lomo de cerdo en cubos","1/2 taza de maicena para rebozar","1 huevo","1 pimiento rojo y 1 verde en trozos","1 taza de piña en trozos","Para la salsa: 4 cdas de kétchup, 3 de vinagre, 3 de azúcar, 1 de soya, 1/2 taza de agua, 1 cdita de maicena","Aceite para freír"],pasos:["Pasa los cubos de cerdo por huevo y maicena, y fríelos hasta que estén dorados y crujientes.","Mezcla los ingredientes de la salsa.","Saltea los pimientos 2 minutos en el wok y agrega la piña.","Vierte la salsa y cocina hasta que espese y brille.","Incorpora el cerdo, mezcla para cubrir y sirve de inmediato con arroz."],ilu:{t:"plato",c:["#C0532B","#E0863B","#9DBE6E"]}},
{id:"cn-04",pais:"China",nombre:"Mapo tofu",desc:"Tofu sedoso en salsa picante de Sichuan con carne y pimienta que adormece los labios.",tiempo:30,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["500 g de tofu suave en cubos","150 g de carne molida de cerdo o res","2 cdas de pasta de poroto con ají (doubanjiang)","1 cda de jengibre y 2 dientes de ajo picados","1 cdita de pimienta de Sichuan tostada y molida","1 taza de caldo","1 cdita de maicena disuelta","2 cebollines","Aceite y salsa de soya"],pasos:["Blanquea el tofu 2 minutos en agua con sal para que no se rompa.","Sofríe la carne hasta dorar, agrega el doubanjiang, ajo y jengibre.","Vierte el caldo y la soya, e incorpora el tofu con cuidado.","Cocina 5 minutos y espesa con la maicena disuelta.","Termina con la pimienta de Sichuan y cebollín; sirve con arroz blanco."],ilu:{t:"bowl",c:["#C0392B","#F2E8D5","#5C8A4E"]}},
{id:"cn-05",pais:"China",nombre:"Pollo Kung Pao",desc:"Pollo salteado con maní, ají seco y salsa agridulce de Sichuan, equilibrio de picante y dulce.",tiempo:35,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["500 g de pechuga de pollo en cubos","1/2 taza de maní tostado","8 ajíes secos en trozos","1 cdita de pimienta de Sichuan","3 cebollines en trozos","Marinada: 1 cda de soya, 1 de vino de arroz, 1 cdita de maicena","Salsa: 2 cdas de soya, 1 de vinagre negro, 1 de azúcar, 1 cdita de maicena, 3 cdas de agua","Ajo, jengibre y aceite"],pasos:["Marina el pollo 15 minutos.","Saltea los ajíes secos y la pimienta de Sichuan en aceite hasta que perfumen.","Agrega el pollo y saltéalo a fuego máximo hasta dorar.","Suma ajo, jengibre y cebollín, y vierte la salsa mezclada.","Cuando espese y brille, incorpora el maní y sirve con arroz."],ilu:{t:"plato",c:["#B5482F","#C9A36A","#5C8A4E"]}},
{id:"cn-06",pais:"China",nombre:"Sopa wonton",desc:"Caldo claro y reconfortante con wontones de cerdo y camarón hechos a mano.",tiempo:60,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["30 láminas de masa para wonton","200 g de carne molida de cerdo","150 g de camarones picados","1 cda de jengibre rallado","2 cebollines picados","1 cda de salsa de soya y 1 cdita de aceite de sésamo","1,5 litros de caldo de pollo claro","Hojas de bok choy o espinaca","Sal y pimienta blanca"],pasos:["Mezcla cerdo, camarón, jengibre, cebollín, soya y aceite de sésamo.","Pon poco relleno en cada lámina, moja los bordes y cierra apretando como un atadito.","Hierve el caldo y sazónalo con sal y pimienta blanca.","Cocina los wontones en el caldo 4–5 minutos hasta que floten.","Agrega las hojas verdes al final y sirve con cebollín y unas gotas de sésamo."],ilu:{t:"bowl",c:["#E8D9B5","#F2E8D5","#5C8A4E"]}},
{id:"cn-07",pais:"China",nombre:"Pato pekinés",desc:"Pato de piel laqueada y crujiente servido con panqueques, cebollín y salsa hoisin.",tiempo:300,porciones:6,dificultad:"Alta",tipo:["comida"],nivel:5,ingredientes:["1 pato entero","2 cdas de miel o maltosa","2 cdas de vinagre de arroz","1 cda de salsa de soya","1 cdita de cinco especias chinas","Panqueques mandarín","1 pepino y 4 cebollines en bastones","Salsa hoisin"],pasos:["Escalda el pato con agua hirviendo para tensar la piel y sécalo muy bien.","Píntalo con la mezcla de miel, vinagre, soya y cinco especias.","Déjalo secar colgado o en rejilla en el refrigerador 12–24 horas: piel seca = piel crujiente.","Hornea a 180 °C por 70–80 minutos, girando, hasta que la piel quede laqueada y crocante.","Corta en láminas finas y sirve envuelto en panqueques con pepino, cebollín y hoisin."],ilu:{t:"plato",c:["#8C3A2A","#C0532B","#9DBE6E"]}},
{id:"cn-08",pais:"China",nombre:"Baozi de cerdo",desc:"Pancitos al vapor esponjosos rellenos de cerdo jugoso, el desayuno de toda China.",tiempo:150,porciones:6,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["500 g de harina","250 ml de agua tibia","5 g de levadura seca","1 cda de azúcar","400 g de carne molida de cerdo","2 cebollines y 1 cda de jengibre","2 cdas de salsa de soya y 1 de salsa de ostras","1 cdita de aceite de sésamo","Papel encerado en cuadritos para el vapor"],pasos:["Haz la masa con harina, agua, levadura y azúcar; amasa y deja levar 1 hora.","Mezcla el relleno: cerdo, cebollín, jengibre, salsas y sésamo.","Divide la masa en bolitas, estira discos con el borde más fino que el centro.","Rellena y cierra plegando hacia el centro en forma de moño.","Deja levar 20 minutos sobre los papelitos y cocina al vapor 12–15 minutos."],ilu:{t:"pan",c:["#FFF6E3","#F2E8D5","#C0392B"]}},
{id:"cn-09",pais:"China",nombre:"Té de jazmín",desc:"Té verde perfumado con flores de jazmín, preparado a la temperatura justa.",tiempo:10,porciones:2,dificultad:"Fácil",tipo:["bebida"],nivel:1,ingredientes:["2 cditas de té de jazmín en hebras","500 ml de agua","Opcional: 1 cdita de miel"],pasos:["Calienta el agua hasta 80 °C (cuando empiezan a subir burbujitas pequeñas, antes de hervir).","Enjuaga las hebras con un chorrito de agua caliente y descártalo: despierta el té.","Infusiona 2–3 minutos, no más, para que no amargue.","Cuela y sirve; las mismas hebras aguantan 2 o 3 infusiones más.","Bebe caliente, idealmente sin endulzar, acompañando dumplings o baozi."],ilu:{t:"taza",c:["#D9E3B5","#F2E8D5","#FFF6E3"]}},
{id:"cn-10",pais:"China",nombre:"Bolitas de sésamo (jian dui)",desc:"Bolas fritas de arroz glutinoso rellenas de pasta dulce de poroto rojo, cubiertas de ajonjolí.",tiempo:60,porciones:6,dificultad:"Media",tipo:["postre"],nivel:3,ingredientes:["250 g de harina de arroz glutinoso","80 g de azúcar","180 ml de agua tibia","200 g de pasta dulce de poroto rojo (anko)","1/2 taza de semillas de sésamo","Aceite para freír"],pasos:["Disuelve el azúcar en el agua tibia y mezcla con la harina hasta formar una masa suave.","Toma porciones, aplánalas y rellena con una bolita de pasta de poroto; cierra bien.","Humedece apenas y rueda por las semillas de sésamo presionando.","Fríe a fuego medio-bajo girando: deben inflarse y dorar parejo (8 minutos).","Escurre y sirve tibias: crujientes por fuera, chiclosas por dentro."],ilu:{t:"pan",c:["#D9A05B","#E8C36A","#F2E8D5"]}},
{id:"jp-01",pais:"Japón",nombre:"Sushi maki",desc:"Rollos de arroz avinagrado con salmón y palta envueltos en alga nori, hechos en casa.",tiempo:80,porciones:4,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["2 tazas de arroz para sushi","4 cdas de vinagre de arroz, 2 de azúcar y 1 cdita de sal","4 láminas de alga nori","200 g de salmón fresco de calidad en bastones","1 palta en láminas","1 pepino en bastones","Salsa de soya, wasabi y jengibre encurtido","Esterilla de bambú"],pasos:["Lava el arroz hasta que el agua salga clara y cuécelo; mézclalo tibio con el vinagre, azúcar y sal.","Pon una lámina de nori sobre la esterilla y extiende arroz dejando un borde libre.","Coloca salmón, palta y pepino en línea.","Enrolla apretando con la esterilla y sella el borde con agua.","Corta cada rollo en 8 con cuchillo húmedo y sirve con soya, wasabi y jengibre."],ilu:{t:"pan",c:["#F2EDE3","#2E3A2E","#D98A8A"]}},
{id:"jp-02",pais:"Japón",nombre:"Ramen de miso",desc:"Fideos en caldo profundo de miso con cerdo, huevo marinado y cebollín.",tiempo:120,porciones:4,dificultad:"Alta",tipo:["comida"],nivel:4,ingredientes:["4 porciones de fideos para ramen","1,5 litros de caldo de pollo y cerdo","4 cdas de pasta de miso","2 cdas de salsa de soya y 1 de mirin","300 g de panceta de cerdo (chashu)","4 huevos","1 taza de brotes de soya","2 cebollines y alga nori","1 cdita de jengibre y ajo rallados","Aceite de sésamo"],pasos:["Cocina la panceta enrollada a fuego bajo en soya, mirin y agua durante 1 hora; córtala en láminas.","Cuece los huevos 6,5 minutos, pélalos y marínalos en la salsa del cerdo.","Disuelve el miso con jengibre y ajo en el caldo caliente sin que hierva fuerte.","Cuece los fideos aparte y repártelos en los tazones.","Vierte el caldo y monta con chashu, medio huevo, brotes, cebollín y nori."],ilu:{t:"bowl",c:["#C9913D","#F2E3C2","#2E3A2E"]}},
{id:"jp-03",pais:"Japón",nombre:"Okonomiyaki",desc:"Tortilla-panqueque de col con panceta, salsas y katsuobushi que baila con el calor.",tiempo:40,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["4 tazas de col picada fina","1 taza de harina","2/3 taza de caldo dashi o agua","2 huevos","8 láminas finas de panceta","Salsa okonomiyaki (o mezcla de salsa inglesa, kétchup y soya)","Mayonesa japonesa","Katsuobushi (láminas de bonito seco) y alga aonori","2 cebollines"],pasos:["Mezcla harina, caldo y huevos; incorpora la col y el cebollín.","Vierte la mezcla en sartén formando un disco grueso y pon la panceta encima.","Cocina 5 minutos, voltea y cocina 5 minutos más presionando apenas.","Vuelve a girar para que la panceta quede arriba y crujiente.","Pinta con la salsa, dibuja líneas de mayonesa y corona con katsuobushi y aonori."],ilu:{t:"arepa",c:["#E0B45B","#C98B5A","#8C3A2A"]}},
{id:"jp-04",pais:"Japón",nombre:"Tempura de camarón y verduras",desc:"Fritura japonesa de rebozado ligerísimo y crujiente, con salsa tentsuyu para mojar.",tiempo:45,porciones:4,dificultad:"Media",tipo:["comida"],nivel:3,ingredientes:["12 camarones grandes limpios","1 zanahoria, 1 berenjena y 1 camote en láminas","100 g de harina (más extra para espolvorear)","1 huevo","200 ml de agua HELADA (con hielo)","Aceite vegetal para freír","Salsa tentsuyu: dashi, soya y mirin","Nabo rallado (opcional)"],pasos:["Haz cortes en la panza de los camarones para que queden rectos.","Mezcla apenas el huevo con el agua helada y la harina: deben quedar grumos, no batas de más.","Espolvorea los ingredientes con harina y pásalos por la masa fría.","Fríe en aceite a 175 °C en tandas pequeñas hasta que estén apenas dorados y crujientes.","Escurre sobre rejilla y sirve de inmediato con la salsa tibia y nabo rallado."],ilu:{t:"brocheta",c:["#E8C36A","#E0B45B","#D98A8A"]}},
{id:"jp-05",pais:"Japón",nombre:"Yakitori",desc:"Brochetas de pollo a la parrilla lacadas con salsa tare dulce y brillante.",tiempo:40,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["600 g de muslos de pollo deshuesados en trozos","4 cebollines en trozos de 3 cm","Para el tare: 1/2 taza de salsa de soya, 1/2 de mirin, 2 cdas de sake, 2 cdas de azúcar","Palitos de brocheta remojados en agua","Shichimi togarashi (opcional)"],pasos:["Hierve los ingredientes del tare 10 minutos hasta que espese ligeramente.","Ensarta el pollo alternando con trozos de cebollín.","Asa las brochetas a fuego medio-alto girándolas.","Pinta con el tare varias veces durante los últimos minutos para lacarlas.","Sirve con un toque de shichimi y más tare por encima."],ilu:{t:"brocheta",c:["#C98B5A","#9DBE6E","#8C3A2A"]}},
{id:"jp-06",pais:"Japón",nombre:"Onigiri",desc:"Triángulos de arroz rellenos de atún con mayonesa o ciruela, abrazados por alga nori.",tiempo:30,porciones:4,dificultad:"Fácil",tipo:["comida"],nivel:1,ingredientes:["3 tazas de arroz japonés cocido","1 lata de atún con 2 cdas de mayonesa japonesa","Umeboshi (ciruela encurtida, opcional)","Láminas de alga nori en tiras","Sal","Semillas de sésamo (opcional)"],pasos:["Humedece tus manos con agua y frótalas con un poco de sal.","Toma arroz tibio, haz un hueco y pon el relleno al centro.","Cierra y moldea presionando suavemente en forma de triángulo.","Envuelve la base con una tira de nori.","Sirve a temperatura ambiente: el clásico de las loncheras japonesas."],ilu:{t:"porcion",c:["#F2EDE3","#FFF6E3","#2E3A2E"]}},
{id:"jp-07",pais:"Japón",nombre:"Curry japonés",desc:"Curry espeso y suave con papa, zanahoria y carne sobre arroz: comida casera de Japón.",tiempo:60,porciones:6,dificultad:"Fácil",tipo:["comida"],nivel:2,ingredientes:["500 g de carne de res o pollo en cubos","2 papas grandes en trozos","2 zanahorias en rodajas gruesas","1 cebolla grande en juliana","1 caja de roux de curry japonés (o 3 cdas de curry, 3 de harina y 3 de mantequilla)","1 litro de agua","1 manzana rallada (el secreto dulce)","Arroz blanco para servir"],pasos:["Dora la carne y la cebolla en una olla.","Agrega papas, zanahorias y el agua; cocina 20 minutos.","Apaga el fuego e incorpora el roux de curry en trozos, removiendo hasta disolver.","Suma la manzana rallada y cocina a fuego bajo 10 minutos hasta que espese.","Sirve sobre arroz blanco; al estilo japonés, el curry a un lado y el arroz al otro."],ilu:{t:"plato",c:["#A8742E","#EFD27A","#C0532B"]}},
{id:"jp-08",pais:"Japón",nombre:"Mochi de fresa (ichigo daifuku)",desc:"Masa elástica de arroz dulce que envuelve una fresa entera con pasta de poroto rojo.",tiempo:50,porciones:6,dificultad:"Media",tipo:["postre"],nivel:3,ingredientes:["150 g de harina de arroz glutinoso (shiratamako o mochiko)","50 g de azúcar","200 ml de agua","6 fresas grandes","200 g de pasta dulce de poroto rojo (anko)","Maicena o almidón para espolvorear"],pasos:["Envuelve cada fresa en una capa de anko.","Mezcla la harina de arroz con azúcar y agua, y cocina al vapor o microondas en tandas cortas, removiendo, hasta que esté translúcida y elástica.","Vuelca la masa sobre abundante maicena.","Divide en porciones, aplana discos con las manos enharinadas.","Envuelve cada fresa con la masa, sella abajo y sirve el mismo día."],ilu:{t:"pan",c:["#FFF6E3","#F2E8F2","#C9425E"]}},
{id:"jp-09",pais:"Japón",nombre:"Dorayaki",desc:"Dos panqueques esponjosos tipo castella unidos con pasta dulce de poroto rojo.",tiempo:35,porciones:4,dificultad:"Fácil",tipo:["postre"],nivel:2,ingredientes:["2 huevos","80 g de azúcar","1 cda de miel","100 g de harina","1/2 cdita de polvo de hornear","2 cdas de agua","200 g de pasta dulce de poroto rojo (anko)"],pasos:["Bate los huevos con el azúcar y la miel hasta que espumen.","Incorpora la harina tamizada con el polvo de hornear y el agua: la mezcla debe caer en cinta.","Reposa 15 minutos.","Cocina discos de 8 cm en sartén antiadherente a fuego medio-bajo: voltea cuando aparezcan burbujas.","Une los discos de a pares con una capa generosa de anko en el centro."],ilu:{t:"arepa",c:["#C9913D","#8C4A5A","#E0B45B"]}},
{id:"jp-10",pais:"Japón",nombre:"Té matcha",desc:"Té verde en polvo batido hasta espumar, preparado con la calma de la ceremonia japonesa.",tiempo:10,porciones:2,dificultad:"Fácil",tipo:["bebida"],nivel:2,ingredientes:["2 cditas de té matcha de calidad","160 ml de agua a 80 °C","Batidor de bambú (chasen) o batidor pequeño","Opcional: leche caliente y miel para versión latte"],pasos:["Tamiza el matcha en el tazón para deshacer los grumos.","Agrega un chorrito de agua caliente (no hirviendo) y forma una pasta.","Vierte el resto del agua.","Bate en forma de W con energía hasta lograr una espuma fina y brillante.","Bebe de inmediato; para un matcha latte, completa con leche caliente y miel."],ilu:{t:"taza",c:["#7A9E4E","#F2EDE3","#D9E3B5"]}},
];
